1	package fan.summer.Registrar;
2	
3	import com.toolbox.api.ToolPlugin;
4	import com.toolbox.plugin.PluginLoader;
5	import com.toolbox.plugin.PluginRegistry;
6	import javafx.geometry.Insets;
7	import javafx.geometry.Pos;
8	import javafx.scene.Node;
9	import javafx.scene.control.Button;
10	import javafx.scene.control.Label;
11	import javafx.scene.control.TextArea;
12	import javafx.scene.control.TextField;
13	import javafx.scene.layout.HBox;
14	import javafx.scene.layout.Priority;
15	import javafx.scene.layout.Region;
16	import javafx.scene.layout.VBox;
17	
18	/**
19	 * Built-in tool registrar.
20	 * Built-in tools implement the same ToolPlugin interface as external plugins, transparent to the main program.
21	 * Directly injected into PluginRegistry, bypassing PluginLoader JAR process.
22	 */
23	public class BuiltinToolRegistrar {
24	
25	    public static void register(PluginLoader loader, PluginRegistry registry) {
26	        // Built-in tools are directly added到 registry（绕过 loader，无需 JAR）
27	        registry.getPlugins().addAll(
28	            jsonFormatter(),
29	            base64Tool(),
30	            hashTool(),
31	            colorConverter(),
32	            markdownEditor()
33	        );
34	    }
35	
36	    // ════════════════════════════════════════════════════
37	    // Tool implementations
38	    // ════════════════════════════════════════════════════
39	
40	    // ── JSON Formatter ───────────────────────────────────────
41	
42	    private static ToolPlugin jsonFormatter() {
43	        return new SimpleToolPlugin(
44	            "builtin.json-formatter", "JSON Formatter",
45	            "Format, compress, and validate JSON data",
46	            "dev", "1.0.0", "{ }", "ic-blue"
47	        ) {
48	            @Override public Node createView() {
49	                TextArea input  = styledTextArea("Paste JSON......");
50	                TextArea output = styledTextArea("");
51	                output.setEditable(false);
52	
53	                Button formatBtn  = actionButton("Format", "#5b8cf7");
54	                Button compactBtn = actionButton("Compact",   "rgba(255,255,255,0.12)");
55	                Button clearBtn   = actionButton("Clear",   "rgba(255,255,255,0.08)");
56	
57	                formatBtn.setOnAction(e -> {
58	                    try {
59	                        // 简单演示：用换行和缩进模拟Format
60	                        String raw = input.getText().trim();
61	                        output.setText(prettyPrint(raw));
62	                        output.setStyle(output.getStyle());
63	                    } catch (Exception ex) {
64	                        output.setText("❌ Invalid JSON：" + ex.getMessage());
65	                    }
66	                });
67	                compactBtn.setOnAction(e ->
68	                    output.setText(input.getText().replaceAll("\\s+", ""))
69	                );
70	                clearBtn.setOnAction(e -> { input.clear(); output.clear(); });
71	
72	                HBox btnRow = new HBox(8, formatBtn, compactBtn, clearBtn);
73	                btnRow.setPadding(new Insets(0, 0, 12, 0));
74	
75	                VBox left  = new VBox(6, sectionLabel("Input"), input);
76	                VBox right = new VBox(6, sectionLabel("Output"), output);
77	                VBox.setVgrow(input,  Priority.ALWAYS);
78	                VBox.setVgrow(output, Priority.ALWAYS);
79	                HBox.setHgrow(left,   Priority.ALWAYS);
80	                HBox.setHgrow(right,  Priority.ALWAYS);
81	
82	                HBox editors = new HBox(12, left, right);
83	                HBox.setHgrow(editors, Priority.ALWAYS);
84	                VBox.setVgrow(editors, Priority.ALWAYS);
85	
86	                VBox root = new VBox(12, btnRow, editors);
87	                root.setPadding(new Insets(20));
88	                root.setStyle("-fx-background-color: transparent;");
89	                VBox.setVgrow(root, Priority.ALWAYS);
90	                return root;
91	            }
92	
93	            private String prettyPrint(String json) {
94	                StringBuilder sb = new StringBuilder();
95	                int indent = 0;
96	                boolean inString = false;
97	                for (char c : json.toCharArray()) {
98	                    if (c == '"' && (sb.isEmpty() || sb.charAt(sb.length()-1) != '\\'))
99	                        inString = !inString;
100	                    if (!inString) {
101	                        if (c == '{' || c == '[') {
102	                            sb.append(c).append('\n');
103	                            indent += 2;
104	                            sb.append(" ".repeat(indent));
105	                            continue;
106	                        } else if (c == '}' || c == ']') {
107	                            sb.append('\n');
108	                            indent = Math.max(0, indent - 2);
109	                            sb.append(" ".repeat(indent)).append(c);
110	                            continue;
111	                        } else if (c == ',') {
112	                            sb.append(c).append('\n').append(" ".repeat(indent));
113	                            continue;
114	                        } else if (c == ':') {
115	                            sb.append(": ");
116	                            continue;
117	                        } else if (c == ' ' || c == '\n' || c == '\r' || c == '\t') {
118	                            continue;
119	                        }
120	                    }
121	                    sb.append(c);
122	                }
123	                return sb.toString();
124	            }
125	        };
126	    }
127	
128	    // ── Base64 Encode/Decode ─────────────────────────────────────
129	
130	    private static ToolPlugin base64Tool() {
131	        return new SimpleToolPlugin(
132	            "builtin.base64", "Base64",
133	            "Base64 Encode/Decode，支持文本与文件",
134	            "dev", "1.0.0", "64", "ic-teal"
135	        ) {
136	            @Override public Node createView() {
137	                TextArea input  = styledTextArea("Input文本...");
138	                TextArea output = styledTextArea("");
139	                output.setEditable(false);
140	
141	                Button encodeBtn = actionButton("Encode →", "#5b8cf7");
142	                Button decodeBtn = actionButton("← Decode", "rgba(255,255,255,0.12)");
143	                Button swapBtn   = actionButton("↕ Swap", "rgba(255,255,255,0.08)");
144	
145	                encodeBtn.setOnAction(e -> {
146	                    try {
147	                        byte[] encoded = java.util.Base64.getEncoder()
148	                            .encode(input.getText().getBytes(java.nio.charset.StandardCharsets.UTF_8));
149	                        output.setText(new String(encoded));
150	                    } catch (Exception ex) { output.setText("Error：" + ex.getMessage()); }
151	                });
152	                decodeBtn.setOnAction(e -> {
153	                    try {
154	                        byte[] decoded = java.util.Base64.getDecoder()
155	                            .decode(input.getText().trim());
156	                        output.setText(new String(decoded, java.nio.charset.StandardCharsets.UTF_8));
157	                    } catch (Exception ex) { output.setText("❌ 无效 Base64"); }
158	                });
159	                swapBtn.setOnAction(e -> {
160	                    String tmp = input.getText();
161	                    input.setText(output.getText());
162	                    output.setText(tmp);
163	                });
164	
165	                HBox btnRow = new HBox(8, encodeBtn, decodeBtn, swapBtn);
166	                btnRow.setPadding(new Insets(0, 0, 12, 0));
167	
168	                VBox left  = new VBox(6, sectionLabel("Input"), input);
169	                VBox right = new VBox(6, sectionLabel("Output"), output);
170	                VBox.setVgrow(input, Priority.ALWAYS);
171	                VBox.setVgrow(output, Priority.ALWAYS);
172	                HBox.setHgrow(left, Priority.ALWAYS);
173	                HBox.setHgrow(right, Priority.ALWAYS);
174	
175	                HBox editors = new HBox(12, left, right);
176	                VBox.setVgrow(editors, Priority.ALWAYS);
177	                VBox root = new VBox(12, btnRow, editors);
178	                root.setPadding(new Insets(20));
179	                root.setStyle("-fx-background-color: transparent;");
180	                return root;
181	            }
182	        };
183	    }
184	
185	    // ── Hash 计算 ─────────────────────────────────────────
186	
187	    private static ToolPlugin hashTool() {
188	        return new SimpleToolPlugin(
189	            "builtin.hash", "Hash Calculator",
190	            "MD5 / SHA-1 / SHA-256 / SHA-512",
191	            "dev", "1.0.0", "#", "ic-amber"
192	        ) {
193	            @Override public Node createView() {
194	                TextArea input = styledTextArea("Input文本...");
195	
196	                String[][] algos = {{"MD5","MD5"},{"SHA-1","SHA-1"},{"SHA-256","SHA-256"},{"SHA-512","SHA-512"}};
197	                VBox results = new VBox(8);
198	
199	                Button calcBtn = actionButton("Calculate Hash", "#5b8cf7");
200	                calcBtn.setOnAction(e -> {
201	                    results.getChildren().clear();
202	                    for (String[] a : algos) {
203	                        try {
204	                            java.security.MessageDigest md =
205	                                java.security.MessageDigest.getInstance(a[1]);
206	                            byte[] hash = md.digest(
207	                                input.getText().getBytes(java.nio.charset.StandardCharsets.UTF_8));
208	                            StringBuilder hex = new StringBuilder();
209	                            for (byte b : hash) hex.append(String.format("%02x", b));
210	                            results.getChildren().add(hashRow(a[0], hex.toString()));
211	                        } catch (Exception ex) {
212	                            results.getChildren().add(hashRow(a[0], "Error"));
213	                        }
214	                    }
215	                });
216	
217	                VBox root = new VBox(12,
218	                    sectionLabel("Input文本"), input,
219	                    calcBtn, sectionLabel("Result"), results
220	                );
221	                VBox.setVgrow(input, Priority.ALWAYS);
222	                root.setPadding(new Insets(20));
223	                root.setStyle("-fx-background-color: transparent;");
224	                return root;
225	            }
226	
227	            private HBox hashRow(String algo, String value) {
228	                Label algoLabel = new Label(algo);
229	                algoLabel.setStyle(
230	                    "-fx-text-fill: rgba(255,255,255,0.45); -fx-font-size: 11px;" +
231	                    "-fx-min-width: 60px; -fx-font-family: 'SF Mono','Consolas',monospace;"
232	                );
233	                Label valueLabel = new Label(value);
234	                valueLabel.setStyle(
235	                    "-fx-text-fill: rgba(255,255,255,0.85); -fx-font-size: 11px;" +
236	                    "-fx-font-family: 'SF Mono','Consolas',monospace;"
237	                );
238	                valueLabel.setMaxWidth(Double.MAX_VALUE);
239	                HBox.setHgrow(valueLabel, Priority.ALWAYS);
240	
241	                Button copy = new Button("Copy");
242	                copy.setStyle(
243	                    "-fx-background-color: rgba(255,255,255,0.08); -fx-border-width: 0;" +
244	                    "-fx-text-fill: rgba(255,255,255,0.5); -fx-font-size: 10px;" +
245	                    "-fx-background-radius: 4; -fx-cursor: hand; -fx-padding: 2 8 2 8;"
246	                );
247	                copy.setOnAction(e -> {
248	                    javafx.scene.input.Clipboard.getSystemClipboard().setContent(
249	                        new javafx.scene.input.ClipboardContent() {{ putString(value); }}
250	                    );
251	                    copy.setText("✓");
252	                    javafx.animation.PauseTransition pt =
253	                        new javafx.animation.PauseTransition(javafx.util.Duration.seconds(1.5));
254	                    pt.setOnFinished(ev -> copy.setText("Copy"));
255	                    pt.play();
256	                });
257	
258	                HBox row = new HBox(10, algoLabel, valueLabel, copy);
259	                row.setAlignment(Pos.CENTER_LEFT);
260	                row.setStyle(
261	                    "-fx-background-color: rgba(255,255,255,0.04);" +
262	                    "-fx-background-radius: 8; -fx-padding: 10 12 10 12;"
263	                );
264	                return row;
265	            }
266	        };
267	    }
268	
269	    // ── Color Converter ──────────────────────────────────────────
270	
271	    private static ToolPlugin colorConverter() {
272	        return new SimpleToolPlugin(
273	            "builtin.color", "Color Converter",
274	            "HEX / RGB / HSL conversion with live preview",
275	            "image", "1.0.0", "◉", "ic-pink"
276	        ) {
277	            @Override public Node createView() {
278	                TextField hexField = styledField("#5b8cf7");
279	                TextField rgbField = styledField("91, 140, 247");
280	                TextField hslField = styledField("220°, 90%, 66%");
281	
282	                Region preview = new Region();
283	                preview.setPrefSize(80, 80);
284	                preview.setMinSize(80, 80);
285	                preview.setStyle("-fx-background-radius: 16; -fx-background-color: #5b8cf7;");
286	
287	                Runnable updatePreview = () -> {
288	                    try {
289	                        String hex = hexField.getText().trim();
290	                        if (!hex.startsWith("#")) hex = "#" + hex;
291	                        preview.setStyle("-fx-background-radius: 16; -fx-background-color: " + hex + ";");
292	                        javafx.scene.paint.Color c = javafx.scene.paint.Color.web(hex);
293	                        rgbField.setText(String.format("%.0f, %.0f, %.0f",
294	                            c.getRed()*255, c.getGreen()*255, c.getBlue()*255));
295	                        hslField.setText(String.format("%.0f°, %.0f%%, %.0f%%",
296	                            c.getHue(), c.getSaturation()*100, c.getBrightness()*100));
297	                    } catch (Exception ignored) {}
298	                };
299	                hexField.textProperty().addListener((o, oldV, newV) -> updatePreview.run());
300	
301	                VBox fields = new VBox(10,
302	                    fieldRow("HEX",  hexField),
303	                    fieldRow("RGB",  rgbField),
304	                    fieldRow("HSL",  hslField)
305	                );
306	                HBox.setHgrow(fields, Priority.ALWAYS);
307	
308	                HBox top = new HBox(20, preview, fields);
309	                top.setAlignment(Pos.CENTER_LEFT);
310	
311	                VBox root = new VBox(20, sectionLabel("Color Converter"), top);
312	                root.setPadding(new Insets(20));
313	                root.setStyle("-fx-background-color: transparent;");
314	                updatePreview.run();
315	                return root;
316	            }
317	
318	            private HBox fieldRow(String label, TextField field) {
319	                Label l = new Label(label);
320	                l.setStyle("-fx-text-fill: rgba(255,255,255,0.40); -fx-min-width: 40px; -fx-font-size: 12px;");
321	                HBox.setHgrow(field, Priority.ALWAYS);
322	                HBox row = new HBox(12, l, field);
323	                row.setAlignment(Pos.CENTER_LEFT);
324	                return row;
325	            }
326	
327	            private TextField styledField(String text) {
328	                TextField tf = new TextField(text);
329	                tf.setStyle(
330	                    "-fx-background-color: rgba(255,255,255,0.06);" +
331	                    "-fx-border-color: rgba(255,255,255,0.12); -fx-border-width: 1;" +
332	                    "-fx-border-radius: 8; -fx-background-radius: 8;" +
333	                    "-fx-text-fill: rgba(255,255,255,0.88); -fx-font-size: 13px;" +
334	                    "-fx-padding: 8 12 8 12; -fx-font-family: 'SF Mono','Consolas',monospace;"
335	                );
336	                return tf;
337	            }
338	        };
339	    }
340	
341	    // ── Markdown Editor ───────────────────────────────────
342	
343	    private static ToolPlugin markdownEditor() {
344	        return new SimpleToolPlugin(
345	            "builtin.markdown", "Markdown",
346	            "实时预览 Markdown Editor",
347	            "text", "1.0.0", "M↓", "ic-blue"
348	        ) {
349	            @Override public Node createView() {
350	                TextArea editor = styledTextArea(
351	                    "# Hello ToolBox\n\n" +
352	                    "这是 **Markdown** 编辑器。\n\n" +
353	                    "- 支持 *斜体* 和 **粗体**\n" +
354	                    "- 支持列表\n" +
355	                    "- 支持 `代码`\n\n" +
356	                    "> 引用文本\n"
357	                );
358	
359	                javafx.scene.web.WebView preview = new javafx.scene.web.WebView();
360	                preview.setStyle("-fx-background-color: transparent;");
361	
362	                Runnable render = () -> {
363	                    String md = editor.getText();
364	                    String html = mdToHtml(md);
365	                    String page =
366	                        "<html><head><style>" +
367	                        "body{font-family:-apple-system,sans-serif;color:rgba(255,255,255,0.88);" +
368	                        "background:transparent;padding:16px;font-size:14px;line-height:1.7;}" +
369	                        "code{background:rgba(255,255,255,0.1);border-radius:4px;padding:2px 6px;" +
370	                        "font-family:monospace;}" +
371	                        "blockquote{border-left:3px solid #5b8cf7;margin:0;padding-left:16px;" +
372	                        "color:rgba(255,255,255,0.5);}" +
373	                        "h1,h2,h3{color:rgba(255,255,255,0.95);}" +
374	                        "</style></head><body>" + html + "</body></html>";
375	                    preview.getEngine().loadContent(page);
376	                };
377	
378	                editor.textProperty().addListener((o, oldV, newV) -> render.run());
379	
380	                VBox left  = new VBox(6, sectionLabel("编辑"), editor);
381	                VBox right = new VBox(6, sectionLabel("预览"), preview);
382	                VBox.setVgrow(editor,   Priority.ALWAYS);
383	                VBox.setVgrow(preview,  Priority.ALWAYS);
384	                HBox.setHgrow(left,  Priority.ALWAYS);
385	                HBox.setHgrow(right, Priority.ALWAYS);
386	
387	                HBox root = new HBox(12, left, right);
388	                root.setPadding(new Insets(20));
389	                root.setStyle("-fx-background-color: transparent;");
390	                HBox.setHgrow(root, Priority.ALWAYS);
391	                VBox.setVgrow(root, Priority.ALWAYS);
392	                render.run();
393	                return root;
394	            }
395	
396	            private String mdToHtml(String md) {
397	                return md
398	                    .replaceAll("(?m)^### (.+)$", "<h3>$1</h3>")
399	                    .replaceAll("(?m)^## (.+)$",  "<h2>$1</h2>")
400	                    .replaceAll("(?m)^# (.+)$",   "<h1>$1</h1>")
401	                    .replaceAll("\\*\\*(.+?)\\*\\*", "<strong>$1</strong>")
402	                    .replaceAll("\\*(.+?)\\*",        "<em>$1</em>")
403	                    .replaceAll("`(.+?)`",            "<code>$1</code>")
404	                    .replaceAll("(?m)^> (.+)$",       "<blockquote>$1</blockquote>")
405	                    .replaceAll("(?m)^- (.+)$",       "<li>$1</li>")
406	                    .replaceAll("(?m)^$",             "<br/>");
407	            }
408	        };
409	    }
410	
411	    // ════════════════════════════════════════════════════
412	    // Shared helper methods (static factory)
413	    // ════════════════════════════════════════════════════
414	
415	    private static TextArea styledTextArea(String prompt) {
416	        TextArea ta = new TextArea();
417	        ta.setPromptText(prompt);
418	        ta.setStyle(
419	            "-fx-background-color: rgba(255,255,255,0.04);" +
420	            "-fx-border-color: rgba(255,255,255,0.10); -fx-border-width: 1;" +
421	            "-fx-border-radius: 10; -fx-background-radius: 10;" +
422	            "-fx-text-fill: rgba(255,255,255,0.88);" +
423	            "-fx-font-size: 13px; -fx-font-family: 'SF Mono','Consolas',monospace;" +
424	            "-fx-control-inner-background: transparent; -fx-highlight-fill: #5b8cf7;" +
425	            "-fx-padding: 12;"
426	        );
427	        ta.setWrapText(true);
428	        VBox.setVgrow(ta, Priority.ALWAYS);
429	        return ta;
430	    }
431	
432	    private static Button actionButton(String text, String bg) {
433	        Button btn = new Button(text);
434	        btn.setStyle(
435	            "-fx-background-color: " + bg + ";" +
436	            "-fx-text-fill: rgba(255,255,255,0.88); -fx-font-size: 13px;" +
437	            "-fx-background-radius: 8; -fx-border-width: 0;" +
438	            "-fx-padding: 8 18 8 18; -fx-cursor: hand;"
439	        );
440	        return btn;
441	    }
442	
443	    private static Label sectionLabel(String text) {
444	        Label l = new Label(text.toUpperCase());
445	        l.setStyle(
446	            "-fx-text-fill: rgba(255,255,255,0.28); -fx-font-size: 10px;" +
447	            "-fx-font-weight: bold; -fx-letter-spacing: 0.08em;"
448	        );
449	        return l;
450	    }
451	
452	    // ════════════════════════════════════════════════════
453	    // Internal abstract base class: reduce built-in tool boilerplate
454	    // ════════════════════════════════════════════════════
455	
456	    private abstract static class SimpleToolPlugin implements ToolPlugin {
457	        private final String id, name, desc, cat, ver, icon, iconStyle;
458	
459	        SimpleToolPlugin(String id, String name, String desc,
460	                         String cat, String ver, String icon, String iconStyle) {
461	            this.id = id; this.name = name; this.desc = desc;
462	            this.cat = cat; this.ver = ver; this.icon = icon; this.iconStyle = iconStyle;
463	        }
464	
465	        @Override public String getId()          { return id; }
466	        @Override public String getName()        { return name; }
467	        @Override public String getDescription() { return desc; }
468	        @Override public String getCategory()    { return cat; }
469	        @Override public String getVersion()     { return ver; }
470	        @Override public String getIconText()    { return icon; }
471	        @Override public String getIconStyle()   { return iconStyle; }
472	
473	        // ToolPlugin requires getType() — built-in tools return "builtin"
474	        public String getType() { return "builtin"; }
475	    }
476	}
