196	                config.sheetNames      = names;
197	                config.selectedSheets  = new ArrayList<>(names);
198	                previewLabel.setText("✓ Contains " + names.size() + "  sheets：" +
199	                    names.stream().limit(5).collect(Collectors.joining(", ")) +
200	                    (names.size() > 5 ? " …" : ""));
201	            } catch (Exception ex) {
202	                previewLabel.setText("❌ Failed to read file：" + ex.getMessage());
203	                config.sourceFile = null;
204	            }
205	        }
206	    }
207	
208	    // ════════════════════════════════════════════════════
209	    // Step 2: Split mode
210	    // ════════════════════════════════════════════════════
211	
212	    static class Step2View extends VBox {
213	        private final SplitConfig config;
214	        private VBox detailPane;
215	
216	        // BY_COLUMN 控件
217	        private ComboBox<String> columnCombo;
218	        // BY_ROW_COUNT 控件
219	        private Spinner<Integer> rowSpinner;
220	        // BY_SHEET 控件
221	        private ListView<String> sheetList;
222	
223	        Step2View(SplitConfig config) {
224	            this.config = config;
225	            setSpacing(16);
226	            setStyle("-fx-background-color: transparent;");
227	            build();
228	        }
229	
230	        private void build() {
231	            Label title = sectionTitle("Select split mode");
232	
233	            // Three个单选卡片
234	            ToggleGroup group = new ToggleGroup();
235	            VBox modeCards = new VBox(8,
236	                modeCard(group, SplitConfig.SplitMode.BY_SHEET,
237	                    "⊞  Split by sheet", "Each sheet outputs one independent file"),
238	                modeCard(group, SplitConfig.SplitMode.BY_COLUMN,
239	                    "🔤  Split by column value",  "Group by different values in a column, one file per group"),
240	                modeCard(group, SplitConfig.SplitMode.BY_ROW_COUNT,
241	                    "📏  Split by row count",  "Output one file every N rows")
242	            );
243	
244	            // Default select first
245	            ((RadioButton) modeCards.getChildren().get(0)
246	                .lookup(".radio-button") != null
247	                ? modeCards.getChildren().get(0)
248	                : modeCards.getChildren().get(0))
249	                .getClass(); // Trigger once to ensure initialization
250	
251	            // Select first Toggle
252	            group.getToggles().get(0).setSelected(true);
253	            config.mode = SplitConfig.SplitMode.BY_SHEET;
254	
255	            detailPane = new VBox();
256	            detailPane.setStyle("-fx-background-color: transparent;");
257	
258	            group.selectedToggleProperty().addListener((obs, o, n) -> {
259	                if (n != null) {
260	                    config.mode = (SplitConfig.SplitMode) n.getUserData();
261	                    refreshDetail();
262	                }
263	            });
264	
265	            refreshDetail();
266	            getChildren().addAll(title, modeCards, detailPane);
267	        }
268	
269	        /** When file changes刷新列列表等动态内容 */
270	        void refresh(SplitConfig config) {
271	            refreshDetail();
272	        }
273	
274	        private void refreshDetail() {
275	            detailPane.getChildren().clear();
276	            detailPane.setPadding(new Insets(4, 0, 0, 0));
277	
278	            switch (config.mode) {
279	                case BY_SHEET -> {
280	                    if (config.sheetNames == null || config.sheetNames.isEmpty()) return;
281	                    sheetList = new ListView<>();
282	                    sheetList.getItems().addAll(config.sheetNames);
283	                    sheetList.getSelectionModel().setSelectionMode(SelectionMode.MULTIPLE);
284	                    sheetList.getSelectionModel().selectAll();
285	                    sheetList.setPrefHeight(Math.min(config.sheetNames.size() * 32 + 8, 160));
286	                    sheetList.setStyle(
287	                        "-fx-background-color: rgba(255,255,255,0.04);" +
288	                        "-fx-border-color: rgba(255,255,255,0.10); -fx-border-radius: 8;" +
289	                        "-fx-background-radius: 8; -fx-text-fill: white;"
290	                    );
291	                    sheetList.getSelectionModel().selectedItemProperty().addListener((o, ov, nv) ->
292	                        config.selectedSheets = new ArrayList<>(
293	                            sheetList.getSelectionModel().getSelectedItems())
294	                    );
295	                    detailPane.getChildren().addAll(
296	                        subLabel("Select sheets to export (multiple allowed)"), sheetList
297	                    );
298	                }
299	                case BY_COLUMN -> {
300	                    columnCombo = new ComboBox<>();
301	                    columnCombo.setPromptText("Column to split by...…");
302	                    columnCombo.setMaxWidth(Double.MAX_VALUE);
303	                    columnCombo.setStyle(comboStyle());
304	
305	                    // Read first row header from file
306	                    if (config.sourceFile != null) {
307	                        try (Workbook wb = WorkbookFactory.create(
308	                                config.sourceFile.toFile(), null, true)) {
309	                            Sheet s = wb.getSheetAt(0);
310	                            Row header = s.getRow(s.getFirstRowNum());
311	                            if (header != null) {
312	                                for (int c = header.getFirstCellNum();
313	                                     c < header.getLastCellNum(); c++) {
314	                                    Cell cell = header.getCell(c);
315	                                    if (cell != null) {
316	                                        String val = cell.toString().trim();
317	                                        if (!val.isEmpty()) {
318	                                            columnCombo.getItems().add(val);
319	                                        }
320	                                    }
321	                                }
322	                            }
323	                        } catch (Exception ex) {
324	                            columnCombo.getItems().add("（Read failed：" + ex.getMessage() + "）");
325	                        }
326	                    }
327	
328	                    columnCombo.valueProperty().addListener((o, ov, nv) -> {
329	                        config.splitColumn = nv;
330	                        config.splitColumnIndex = columnCombo.getItems().indexOf(nv);
331	                    });
332	
333	                    detailPane.getChildren().addAll(subLabel("Which column to group by"), columnCombo);
334	                }
335	                case BY_ROW_COUNT -> {
336	                    rowSpinner = new Spinner<>(1, 1_000_000, 1000, 100);
337	                    rowSpinner.setEditable(true);
338	                    rowSpinner.setMaxWidth(Double.MAX_VALUE);
339	                    rowSpinner.setStyle(
340	                        "-fx-background-color: rgba(255,255,255,0.06);" +
341	                        "-fx-border-color: rgba(255,255,255,0.12); -fx-border-radius: 8;"
342	                    );
343	                    rowSpinner.valueProperty().addListener((o, ov, nv) ->
344	                        config.rowsPerFile = nv);
345	                    config.rowsPerFile = 1000;
346	
347	                    detailPane.getChildren().addAll(subLabel("Max rows per file"), rowSpinner);
348	                }
349	            }
350	        }
351	
352	        private HBox modeCard(ToggleGroup group, SplitConfig.SplitMode mode,
353	                              String label, String desc) {
354	            RadioButton rb = new RadioButton();
355	            rb.setToggleGroup(group);
356	            rb.setUserData(mode);
357	            rb.setStyle("-fx-text-fill: transparent;");
358	
359	            Label mainL = new Label(label);
360	            mainL.setStyle("-fx-text-fill: rgba(255,255,255,0.88); -fx-font-size: 13px; -fx-font-weight: 500;");
361	            Label descL = new Label(desc);
362	            descL.setStyle("-fx-text-fill: rgba(255,255,255,0.40); -fx-font-size: 11px;");
363	
364	            VBox text = new VBox(2, mainL, descL);
365	            HBox.setHgrow(text, Priority.ALWAYS);
366	            HBox card = new HBox(10, rb, text);
367	            card.setAlignment(Pos.CENTER_LEFT);
368	            card.setPadding(new Insets(12, 16, 12, 16));
369	            card.setStyle(
370	                "-fx-background-color: rgba(255,255,255,0.04);" +
371	                "-fx-border-color: rgba(255,255,255,0.10); -fx-border-width: 1;" +
372	                "-fx-border-radius: 10; -fx-background-radius: 10; -fx-cursor: hand;"
373	            );
374	            card.setOnMouseClicked(e -> rb.setSelected(true));
375	
376	            rb.selectedProperty().addListener((o, ov, nv) -> {
377	                if (nv) {
378	                    card.setStyle(card.getStyle()
379	                        .replace("rgba(255,255,255,0.04)", "rgba(91,140,247,0.10)")
380	                        .replace("rgba(255,255,255,0.10)", "rgba(91,140,247,0.35)"));
381	                } else {
382	                    card.setStyle(card.getStyle()
383	                        .replace("rgba(91,140,247,0.10)", "rgba(255,255,255,0.04)")
384	                        .replace("rgba(91,140,247,0.35)", "rgba(255,255,255,0.10)"));
385	                }
386	            });
387	
388	            return card;
389	        }
390	    }
391	
392	    // ════════════════════════════════════════════════════
393	    // Step 3: Output settings
394	    // ════════════════════════════════════════════════════
395	
396	    static class Step3View extends VBox {
397	        private final SplitConfig config;
398	        private final Label       dirLabel;
399	
400	        Step3View(SplitConfig config) {
401	            this.config = config;
402	            setSpacing(16);
403	            setStyle("-fx-background-color: transparent;");
404	
405	            Label title = sectionTitle("Output settings");
406	
407	            dirLabel = new Label("No directory selected");
408	            dirLabel.setStyle("-fx-text-fill: rgba(255,255,255,0.40); -fx-font-size: 12px;" +
409	                              "-fx-font-family: 'SF Mono','Consolas',monospace;");
410	            dirLabel.setWrapText(true);
411	
412	            Button dirBtn = glassBtn("📁  Select output directory", true);
413	            dirBtn.setOnAction(e -> {
414	                DirectoryChooser dc = new DirectoryChooser();
415	                dc.setTitle("Select output directory");
416	                // Default to source file directory
417	                if (config.sourceFile != null)
418	                    dc.setInitialDirectory(config.sourceFile.getParent().toFile());
419	                File dir = dc.showDialog(getScene() != null ? getScene().getWindow() : null);
420	                if (dir != null) {
421	                    config.outputDir = dir.toPath();
422	                    dirLabel.setText(dir.getAbsolutePath());
423	                    dirLabel.setStyle(dirLabel.getStyle()
424	                        .replace("rgba(255,255,255,0.40)", "rgba(255,255,255,0.88)"));
425	                }
426	            });
427	
428	            // File name prefix
429	            Label prefixLabel = subLabel("输出File name prefix（可选）");
430	            TextField prefixField = new TextField();
431	            prefixField.setPromptText("example: output → output_Sheet1.xlsx");
432	            prefixField.setStyle(fieldStyle());
433	            prefixField.textProperty().addListener((o, ov, nv) -> config.filePrefix = nv);
434	
435	            // Keep header
436	            CheckBox keepHeader = new CheckBox("按列/行Split时Keep header");
437	            keepHeader.setSelected(true);
438	            keepHeader.setStyle("-fx-text-fill: rgba(255,255,255,0.75); -fx-font-size: 13px;");
439	            keepHeader.selectedProperty().addListener((o, ov, nv) -> config.keepHeader = nv);
440	
441	            getChildren().addAll(
442	                title,
443	                dirBtn, dirLabel,
444	                new Separator() {{ setStyle("-fx-border-color: rgba(255,255,255,0.08);"); }},
445	                prefixLabel, prefixField,
446	                keepHeader
447	            );
448	        }
449	    }
450	
451	    // ════════════════════════════════════════════════════
452	    // Step 4: Execute split + 结果展示
453	    // ════════════════════════════════════════════════════
454	
455	    static class Step4View extends VBox {
456	        private final SplitConfig config;
457	        private final ProgressBar  progressBar;
458	        private final Label        progressLabel;
459	        private final VBox         resultBox;
460	        private boolean started = false;
461	
462	        Step4View(SplitConfig config) {
463	            this.config = config;
464	            setSpacing(16);
465	            setStyle("-fx-background-color: transparent;");
466	
467	            Label title = sectionTitle("Splitting...…");
468	
469	            progressBar = new ProgressBar(0);
470	            progressBar.setMaxWidth(Double.MAX_VALUE);
471	            progressBar.setPrefHeight(6);
472	            progressBar.setStyle("-fx-accent: #5b8cf7; -fx-background-radius: 3; -fx-background-color: rgba(255,255,255,0.08);");
473	
474	            progressLabel = new Label("Preparing...…");
475	            progressLabel.setStyle("-fx-text-fill: rgba(255,255,255,0.55); -fx-font-size: 12px;");
476	
477	            resultBox = new VBox(8);
478	            resultBox.setStyle("-fx-background-color: transparent;");
479	
480	            getChildren().addAll(title, progressBar, progressLabel, resultBox);
481	        }
482	
483	        void startSplit() {
484	            if (started) return;
485	            started = true;
486	            resultBox.getChildren().clear();
487	
488	            Task<ExcelSplitter.SplitResult> task = new Task<>() {
489	                @Override
490	                protected ExcelSplitter.SplitResult call() throws Exception {
491	                    ExcelSplitter splitter = new ExcelSplitter(config, (pct, msg) ->
492	                        Platform.runLater(() -> {
493	                            progressBar.setProgress(pct);
494	                            progressLabel.setText(msg);
495	                        })
496	                    );
497	                    return splitter.split();
498	                }
499	            };
500	
501	            task.setOnSucceeded(e -> showSuccess(task.getValue()));
502	            task.setOnFailed(e  -> showError(task.getException()));
503	
504	            Thread t = new Thread(task);
505	            t.setDaemon(true);
506	            t.start();
507	        }
508	
509	        private void showSuccess(ExcelSplitter.SplitResult result) {
510	            progressBar.setProgress(1.0);
511	            progressBar.setStyle(progressBar.getStyle().replace("#5b8cf7", "#4cd97b"));
512	            progressLabel.setText("✓ Split complete, output " + result.fileCount() + "  files");
513	
514	            resultBox.getChildren().add(subLabel("Output files"));
515	            for (Path p : result.outputFiles()) {
516	                HBox row = new HBox(10);
517	                row.setAlignment(Pos.CENTER_LEFT);
518	                row.setPadding(new Insets(8, 12, 8, 12));
519	                row.setStyle(
520	                    "-fx-background-color: rgba(76,217,123,0.06);" +
521	                    "-fx-border-color: rgba(76,217,123,0.15);" +
522	                    "-fx-border-width: 1; -fx-border-radius: 8; -fx-background-radius: 8;"
523	                );
524	
525	                Label icon = new Label("📄");
526	                Label name = new Label(p.getFileName().toString());
527	                name.setStyle("-fx-text-fill: rgba(255,255,255,0.85); -fx-font-size: 12px;" +
528	                              "-fx-font-family: 'SF Mono','Consolas',monospace;");
529	                HBox.setHgrow(name, Priority.ALWAYS);
530	
531	                Button open = new Button("Open folder");
532	                open.setStyle(
533	                    "-fx-background-color: transparent; -fx-border-color: rgba(76,217,123,0.4);" +
534	                    "-fx-border-width: 1; -fx-border-radius: 5; -fx-text-fill: #4cd97b;" +
535	                    "-fx-font-size: 11px; -fx-padding: 3 8 3 8; -fx-cursor: hand;"
536	                );
537	                open.setOnAction(e -> {
538	                    try {
539	                        java.awt.Desktop.getDesktop().open(p.getParent().toFile());
540	                    } catch (Exception ex) { /* Skip */ }
541	                });
542	
543	                row.getChildren().addAll(icon, name, open);
544	                resultBox.getChildren().add(row);
545	            }
546	        }
547	
548	        private void showError(Throwable err) {
549	            progressBar.setProgress(0);
550	            progressBar.setStyle(progressBar.getStyle().replace("#5b8cf7", "#f25c5c"));
551	            progressLabel.setText("❌ Split failed");
552	
553	            Label errLabel = new Label(err.getMessage());
554	            errLabel.setStyle(
555	                "-fx-text-fill: #f25c5c; -fx-font-size: 12px; -fx-wrap-text: true;" +
556	                "-fx-background-color: rgba(242,92,92,0.08); -fx-padding: 12;" +
557	                "-fx-background-radius: 8;"
558	            );
559	            errLabel.setWrapText(true);
560	            resultBox.getChildren().add(errLabel);
561	        }
562	    }
563	
564	    // ════════════════════════════════════════════════════
565	    // Shared UI tools
566	    // ════════════════════════════════════════════════════
567	
568	    private static Label sectionTitle(String text) {
569	        Label l = new Label(text);
570	        l.setStyle("-fx-text-fill: rgba(255,255,255,0.88); -fx-font-size: 15px; -fx-font-weight: 500;");
571	        return l;
572	    }
573	
574	    static Label subLabel(String text) {
575	        Label l = new Label(text.toUpperCase());
576	        l.setStyle("-fx-text-fill: rgba(255,255,255,0.30); -fx-font-size: 10px;" +
577	                   "-fx-font-weight: bold; -fx-letter-spacing: 0.08em;");
578	        return l;
579	    }
580	
581	    static Button glassBtn(String text, boolean primary) {
582	        Button btn = new Button(text);
583	        if (primary) {
584	            btn.setStyle(
585	                "-fx-background-color: #5b8cf7; -fx-text-fill: white; -fx-font-size: 13px;" +
586	                "-fx-font-weight: 500; -fx-background-radius: 8; -fx-border-width: 0;" +
587	                "-fx-padding: 10 20 10 20; -fx-cursor: hand;"
588	            );
589	        } else {
590	            btn.setStyle(
591	                "-fx-background-color: rgba(255,255,255,0.07);" +
592	                "-fx-border-color: rgba(255,255,255,0.12); -fx-border-width: 1;" +
593	                "-fx-text-fill: rgba(255,255,255,0.75); -fx-font-size: 13px;" +
594	                "-fx-background-radius: 8; -fx-border-radius: 8;" +
595	                "-fx-padding: 10 20 10 20; -fx-cursor: hand;"
596	            );
597	        }
598	        return btn;
599	    }
600	
601	    private static String fieldStyle() {
602	        return "-fx-background-color: rgba(255,255,255,0.05);" +
603	               "-fx-border-color: rgba(255,255,255,0.12); -fx-border-width: 1;" +
604	               "-fx-border-radius: 8; -fx-background-radius: 8;" +
605	               "-fx-text-fill: rgba(255,255,255,0.88); -fx-font-size: 13px; -fx-padding: 9 12 9 12;";
606	    }
607	
608	    private static String comboStyle() {
609	        return "-fx-background-color: rgba(255,255,255,0.05);" +
610	               "-fx-border-color: rgba(255,255,255,0.12); -fx-border-width: 1;" +
611	               "-fx-border-radius: 8; -fx-background-radius: 8; -fx-text-fill: rgba(255,255,255,0.88);";
612	    }
613	}
