1	package fan.summer.app;
2	
3	import com.toolbox.plugin.PluginLoader;
4	import com.toolbox.plugin.PluginRegistry;
5	import com.toolbox.ui.MainWindow;
6	import fan.summer.Registrar.BuiltinToolRegistrar;
7	import javafx.application.Application;
8	import javafx.scene.Scene;
9	import javafx.scene.paint.Color;
10	import javafx.stage.Stage;
11	import javafx.stage.StageStyle;
12	
13	import java.nio.file.Path;
14	import java.nio.file.Paths;
15	
16	/**
17	 * Application entry point.
18	 * Startup sequence:
19	 *   1. Determine plugins/ directory
20	 *   2. Create PluginLoader + PluginRegistry
21	 *   3. Register built-in tools
22	 *   4. Build MainWindow and display
23	 *   5. Start PluginLoader (scan JARs + start file watcher)
24	 */
25	public class SwissKitJApp extends Application {
26	
27	    private MainWindow mainWindow;
28	
29	    @Override
30	    public void start(Stage stage) throws Exception {
31	
32	        // ── Plugin directory (prefer JAR sibling, fallback to working directory during dev) ──
33	        Path pluginsDir = resolvePluginsDir();
34	
35	        // ── Plugin system ──────────────────────────────────────
36	        PluginLoader   loader   = new PluginLoader(pluginsDir);
37	        PluginRegistry registry = new PluginRegistry(loader);
38	
39	        // ── Register built-in tools ──────────────────────────────
40	        BuiltinToolRegistrar.register(loader, registry);
41	
42	        // ── Main window ────────────────────────────────────────
43	        mainWindow = new MainWindow(stage, loader, registry);
44	
45	        // Transparent scene (for rounded window to display correctly)
46	        Scene scene = new Scene(mainWindow, 960, 620);
47	        scene.setFill(Color.TRANSPARENT);
48	        scene.getStylesheets().add(
49	            getClass().getResource("/com/toolbox/css/glass.css").toExternalForm()
50	        );
51	
52	        // Undecorated window (custom titlebar via TitleBar)
53	        stage.initStyle(StageStyle.TRANSPARENT);
54	        stage.setTitle("ToolBox");
55	        stage.setScene(scene);
56	        stage.setMinWidth(800);
57	        stage.setMinHeight(520);
58	        stage.show();
59	
60	        // ── Start plugin loading (after UI is displayed) ────────
61	        loader.start();
62	    }
63	
64	    @Override
65	    public void stop() {
66	        if (mainWindow != null) mainWindow.shutdown();
67	    }
68	
69	    // ── Helper: locate plugins directory ───────────────────────────
70	
71	    private Path resolvePluginsDir() {
72	        // Try JAR sibling directory
73	        try {
74	            Path jar = Paths.get(
75	                SwissKitJApp.class.getProtectionDomain()
76	                    .getCodeSource().getLocation().toURI()
77	            );
78	            Path candidate = jar.getParent().resolve("plugins");
79	            if (candidate.toFile().isDirectory()) return candidate;
80	        } catch (Exception ignored) {}
81	
82	        // Dev mode: plugins/ under working directory
83	        return Paths.get("plugins");
84	    }
85	
86	    public static void main(String[] args) {
87	        launch(args);
88	    }
89	}

