package fan.summer.api.content;

import com.toolbox.api.ToolPlugin;
import javafx.animation.FadeTransition;
import javafx.animation.ParallelTransition;
import javafx.animation.PauseTransition;
import javafx.animation.TranslateTransition;
import javafx.collections.ListChangeListener;
import javafx.collections.ObservableList;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Node;
import javafx.scene.control.Label;
import javafx.scene.control.ScrollPane;
import javafx.scene.control.TextField;
import javafx.scene.layout.*;
import javafx.util.Duration;

import java.util.List;
import java.util.function.Consumer;

/**
 * Main content area.
 * Contains: Search bar / Tool grid / Detail panel / Page transition animations.
 * Bind plugin data via setPlugins(ObservableList), auto-respond to add/remove.
 */
public class ContentArea extends BorderPane {

    // ── Sub-components ────────────────────────────────────────────
    private final TextField   searchField  = new TextField();
    private final FlowPane    toolGrid     = new FlowPane();
    private final DetailPanel detailPanel  = new DetailPanel();
    private final StackPane   pageStack    = new StackPane();
    private final ScrollPane  scrollPane;

    // ── State ──────────────────────────────────────────────
    private ObservableList<ToolPlugin> plugins;
    private String   currentCategory = "all";
    private String   currentQuery    = "";
    private Consumer<ToolPlugin> onLaunch;

    public ContentArea() {
        scrollPane = buildScrollPane();
        buildLayout();
        detailPanel.setOnLaunch(p -> { if (onLaunch != null) onLaunch.accept(p); });
    }

    // ── Public API ──────────────────────────────────────────

    public void setOnLaunch(Consumer<ToolPlugin> handler) { this.onLaunch = handler; }

    /** Bind plugin list, auto-refresh on add/remove */
    public void setPlugins(ObservableList<ToolPlugin> list) {
        this.plugins = list;
        list.addListener((ListChangeListener<ToolPlugin>) c -> refresh());
        refresh();
    }

    /** Switch category display */
    public void showCategory(String categoryId) {
        currentCategory = categoryId;
        searchField.clear();
        currentQuery = "";
        crossFadeTo(scrollPane);
        refresh();
        animateGridIn();
    }

    /** Switch to custom page (e.g. settings, plugin market) */
    public void showPage(Node page, String title) {
        crossFadeTo(page);
        detailPanel.hide();
    }

    /** Back to tool grid home */
    public void showToolGrid() {
        crossFadeTo(scrollPane);
    }

    // ── Layout build ──────────────────────────────────────────

    private void buildLayout() {
        // Search bar
        HBox searchBar = buildSearchBar();
        VBox top = new VBox(searchBar);
        top.setPadding(new Insets(12, 16, 0, 16));
        setTop(top);

        // Center: StackPane (switchable content) + Detail panel
        pageStack.getChildren().add(scrollPane);
        pageStack.setAlignment(Pos.TOP_LEFT);

        HBox center = new HBox(pageStack, detailPanel);
        HBox.setHgrow(pageStack, Priority.ALWAYS);
        setCenter(center);
    }

    private HBox buildSearchBar() {
        Label searchIcon = new Label("🔍");
        searchIcon.setStyle("-fx-font-size: 13px; -fx-text-fill: rgba(255,255,255,0.28);");

        searchField.getStyleClass().add("search-field");
        searchField.setPromptText("Search tools...");
        searchField.setMaxWidth(Double.MAX_VALUE);
        HBox.setHgrow(searchField, Priority.ALWAYS);
        searchField.textProperty().addListener((obs, oldVal, newVal) -> {
            currentQuery = newVal.trim().toLowerCase();
            refresh();
        });

        Label kbdHint = new Label("⌘K");
        kbdHint.setStyle(
            "-fx-font-size: 10px; -fx-text-fill: rgba(255,255,255,0.28);" +
            "-fx-background-color: rgba(255,255,255,0.06);" +
            "-fx-border-color: rgba(255,255,255,0.10); -fx-border-width: 1;" +
            "-fx-border-radius: 4; -fx-background-radius: 4;" +
            "-fx-padding: 1 5 1 5; -fx-font-family: 'SF Mono','Consolas',monospace;"
        );

        HBox bar = new HBox(10, searchIcon, searchField, kbdHint);
        bar.getStyleClass().add("search-bar");
        bar.setAlignment(Pos.CENTER_LEFT);
        bar.setPrefHeight(38);
        return bar;
    }

    private ScrollPane buildScrollPane() {
        // Tool grid
        toolGrid.setHgap(10);
        toolGrid.setVgap(10);
        toolGrid.setPadding(new Insets(16));
        toolGrid.setPrefWrapLength(600);

        VBox wrapper = new VBox(
            sectionHeader("FREQUENT", ""),
            toolGrid
        );
        wrapper.setPadding(new Insets(8, 16, 16, 16));
        wrapper.setSpacing(0);

        ScrollPane sp = new ScrollPane(wrapper);
        sp.getStyleClass().add("content-scroll");
        sp.setFitToWidth(true);
        sp.setHbarPolicy(ScrollPane.ScrollBarPolicy.NEVER);
        sp.setVbarPolicy(ScrollPane.ScrollBarPolicy.AS_NEEDED);
        sp.setStyle("-fx-background-color: transparent; -fx-background: transparent;");
        return sp;
    }

    // ── Grid refresh ──────────────────────────────────────────

    private void refresh() {
        if (plugins == null) return;

        List<ToolPlugin> filtered = plugins.stream()
            .filter(this::matchesCategory)
            .filter(this::matchesQuery)
            .toList();

        toolGrid.getChildren().clear();

        for (int i = 0; i < filtered.size(); i++) {
            ToolPlugin p = filtered.get(i);
            ToolCard card = new ToolCard(p, this::onCardSelect);
            card.setPrefWidth(152);
            card.setPrefHeight(130);

            // Staggered entry delay
            int delay = i * 35;
            card.setOpacity(0);
            PauseTransition pause = new PauseTransition(Duration.millis(delay));
            pause.setOnFinished(e -> {
                FadeTransition ft = new FadeTransition(Duration.millis(240), card);
                ft.setFromValue(0); ft.setToValue(1);
                TranslateTransition tt = new TranslateTransition(Duration.millis(240), card);
                tt.setFromY(10); tt.setToY(0);
                new ParallelTransition(ft, tt).play();
            });
            pause.play();

            toolGrid.getChildren().add(card);
        }

        // Empty state message
        if (filtered.isEmpty()) {
            Label empty = new Label("No matching tools found");
            empty.setStyle("-fx-text-fill: rgba(255,255,255,0.28); -fx-font-size: 13px;");
            empty.setPadding(new Insets(40, 0, 0, 0));
            toolGrid.getChildren().add(empty);
        }
    }

    // ── Filter logic ──────────────────────────────────────────

    private boolean matchesCategory(ToolPlugin p) {
        return switch (currentCategory) {
            case "all"     -> true;
            case "plugins" -> !"builtin".equals(p.getType());
            case "fav"     -> false; // TODO: integrate favorites persistence
            default        -> p.getCategory().equalsIgnoreCase(currentCategory);
        };
    }

    private boolean matchesQuery(ToolPlugin p) {
        if (currentQuery.isEmpty()) return true;
        return p.getName().toLowerCase().contains(currentQuery)
            || p.getDescription().toLowerCase().contains(currentQuery);
    }

    // ── Card selection ──────────────────────────────────────────

    private void onCardSelect(ToolPlugin plugin) {
        detailPanel.show(plugin);
    }

    // ── Page transition animation (cross-fade) ──────────────────────

    private void crossFadeTo(Node next) {
        Node current = pageStack.getChildren().isEmpty()
            ? null : pageStack.getChildren().get(0);

        next.setOpacity(0);
        if (!pageStack.getChildren().contains(next))
            pageStack.getChildren().add(next);
        next.toFront();

        FadeTransition fadeIn = new FadeTransition(Duration.millis(220), next);
        fadeIn.setToValue(1);

        if (current != null && current != next) {
            FadeTransition fadeOut = new FadeTransition(Duration.millis(180), current);
            fadeOut.setToValue(0);
            Node finalCurrent = current;
            fadeOut.setOnFinished(e -> pageStack.getChildren().remove(finalCurrent));
            new ParallelTransition(fadeOut, fadeIn).play();
        } else {
            fadeIn.play();
        }
    }

    private void animateGridIn() {
        // Grid slides in from slightly below
        TranslateTransition tt = new TranslateTransition(Duration.millis(280), toolGrid);
        tt.setFromY(12); tt.setToY(0);
        FadeTransition ft = new FadeTransition(Duration.millis(280), toolGrid);
        ft.setFromValue(0.4); ft.setToValue(1);
        new ParallelTransition(tt, ft).play();
    }

    // ── Helper node factory ──────────────────────────────────────

    private HBox sectionHeader(String title, String action) {
        Label titleLabel = new Label(title.toUpperCase());
        titleLabel.getStyleClass().add("section-title");

        Region spacer = new Region();
        HBox.setHgrow(spacer, Priority.ALWAYS);

        HBox row = new HBox(titleLabel, spacer);
        if (!action.isEmpty()) {
            Label actionLabel = new Label(action);
            actionLabel.setStyle("-fx-text-fill: #5b8cf7; -fx-font-size: 12px; -fx-cursor: hand;");
            row.getChildren().add(actionLabel);
        }
        row.setAlignment(Pos.CENTER_LEFT);
        row.setPadding(new Insets(8, 0, 10, 0));
        return row;
    }
}

package fan.summer.api.content;

import com.toolbox.api.ToolPlugin;
import javafx.animation.Interpolator;
import javafx.animation.KeyFrame;
import javafx.animation.KeyValue;
import javafx.animation.Timeline;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.control.Button;
import javafx.scene.control.Label;
import javafx.scene.control.Separator;
import javafx.scene.layout.*;
import javafx.util.Duration;

import java.util.function.Consumer;

/**
 * Tool detail panel, slides in from right.
 * show(plugin) fills data and expands; hide() collapses.
 */
public class DetailPanel extends VBox {

    private static final double PANEL_WIDTH = 260;

    private final Label   iconLabel   = new Label();
    private final StackPane iconWrap  = new StackPane(iconLabel);
    private final Label   nameLabel   = new Label();
    private final Label   metaLabel   = new Label();
    private final Label   descLabel   = new Label();
    private final Label   versionVal  = new Label();
    private final Label   typeVal     = new Label();
    private final Label   categoryVal = new Label();
    private final Button  launchBtn   = new Button("Launch Tool");
    private final Button  closeBtn    = new Button("✕");

    private Consumer<ToolPlugin> onLaunch;
    private ToolPlugin currentPlugin;
    private boolean    panelOpen = false;

    public DetailPanel() {
        getStyleClass().add("detail-panel");
        setPrefWidth(0);   // Initially collapsed
        setMinWidth(0);
        setMaxWidth(PANEL_WIDTH);

        buildUI();
        setVisible(false);
    }

    // ── Public API ──────────────────────────────────────────

    public void setOnLaunch(Consumer<ToolPlugin> handler) {
        this.onLaunch = handler;
    }

    /** Show plugin details, auto-slides in on first call */
    public void show(ToolPlugin plugin) {
        this.currentPlugin = plugin;
        fillData(plugin);
        if (!panelOpen) slideIn();
    }

    /** Slide out and hide */
    public void hide() {
        if (panelOpen) slideOut();
    }

    public boolean isPanelOpen() { return panelOpen; }

    // ── Build UI ───────────────────────────────────────────

    private void buildUI() {
        iconLabel.setStyle("-fx-font-size: 26px;");
        iconWrap.setPrefSize(56, 56);
        iconWrap.setMinSize(56, 56);
        iconWrap.getStyleClass().add("tool-icon-wrap");
        iconWrap.getStyleClass().add("ic-blue");

        nameLabel.getStyleClass().add("tool-name");
        nameLabel.setStyle("-fx-font-size: 16px;");

        metaLabel.getStyleClass().add("status-text");
        metaLabel.setStyle("-fx-font-size: 11px;");

        descLabel.getStyleClass().add("tool-desc");
        descLabel.setWrapText(true);
        descLabel.setStyle("-fx-font-size: 12.5px;");

        launchBtn.getStyleClass().add("detail-launch-btn");
        launchBtn.setMaxWidth(Double.MAX_VALUE);
        launchBtn.setOnAction(e -> {
            if (onLaunch != null && currentPlugin != null)
                onLaunch.accept(currentPlugin);
        });

        closeBtn.setStyle(
            "-fx-background-color: transparent; -fx-border-width: 0;" +
            "-fx-text-fill: rgba(255,255,255,0.35); -fx-cursor: hand; -fx-font-size: 14px;"
        );
        closeBtn.setOnAction(e -> hide());
        closeBtn.setOnMouseEntered(e ->
            closeBtn.setStyle(closeBtn.getStyle() + "-fx-text-fill: rgba(255,255,255,0.85);"));
        closeBtn.setOnMouseExited(e ->
            closeBtn.setStyle(closeBtn.getStyle().replace("-fx-text-fill: rgba(255,255,255,0.85);", "")));

        HBox topRow = new HBox(closeBtn);
        topRow.setAlignment(Pos.CENTER_RIGHT);

        Separator sep = new Separator();
        sep.setStyle("-fx-border-color: rgba(255,255,255,0.10); -fx-padding: 8 0 8 0;");

        // Property rows
        VBox propsBox = new VBox(6,
            propRow("Version",   versionVal),
            propRow("Type",   typeVal),
            propRow("Category",   categoryVal)
        );

        setSpacing(10);
        setPadding(new Insets(16));
        getChildren().addAll(
            topRow, iconWrap, nameLabel, metaLabel, descLabel,
            launchBtn, sep, propsBox
        );
    }

    private HBox propRow(String key, Label valLabel) {
        Label keyLabel = new Label(key);
        keyLabel.setStyle("-fx-text-fill: rgba(255,255,255,0.30); -fx-font-size: 12px;");
        valLabel.setStyle("-fx-text-fill: rgba(255,255,255,0.55); -fx-font-size: 12px; " +
                          "-fx-font-family: 'SF Mono','Consolas',monospace;");
        Region spacer = new Region();
        HBox.setHgrow(spacer, Priority.ALWAYS);
        return new HBox(keyLabel, spacer, valLabel);
    }

    // ── Data fill ─────────────────────────────────────────

    private void fillData(ToolPlugin p) {
        iconLabel.setText(p.getIconText());
        iconWrap.getStyleClass().removeIf(c -> c.startsWith("ic-"));
        iconWrap.getStyleClass().add(p.getIconStyle());

        nameLabel.setText(p.getName());
        metaLabel.setText("v" + p.getVersion() + " · " + p.getType());
        descLabel.setText(p.getDescription());

        versionVal.setText(p.getVersion());
        typeVal.setText(p.getType());
        categoryVal.setText(categoryName(p.getCategory()));
    }

    private String categoryName(String cat) {
        return switch (cat) {
            case "dev"   -> "Developer Tools";
            case "text"  -> "Text Processing";
            case "image" -> "Image Processing";
            case "net"   -> "Network Tools";
            default      -> cat;
        };
    }

    // ── Slide in / out animations ─────────────────────────

    private void slideIn() {
        panelOpen = true;
        setVisible(true);

        Timeline tl = new Timeline(
            new KeyFrame(Duration.ZERO,
                new KeyValue(prefWidthProperty(), 0),
                new KeyValue(opacityProperty(), 0)
            ),
            new KeyFrame(Duration.millis(300),
                new KeyValue(prefWidthProperty(), PANEL_WIDTH,
                    Interpolator.SPLINE(0.4, 0, 0.2, 1)),
                new KeyValue(opacityProperty(), 1,
                    Interpolator.EASE_OUT)
            )
        );
        tl.play();
    }

    private void slideOut() {
        panelOpen = false;
        Timeline tl = new Timeline(
            new KeyFrame(Duration.ZERO,
                new KeyValue(prefWidthProperty(), PANEL_WIDTH),
                new KeyValue(opacityProperty(), 1)
            ),
            new KeyFrame(Duration.millis(250),
                new KeyValue(prefWidthProperty(), 0,
                    Interpolator.SPLINE(0.4, 0, 0.2, 1)),
                new KeyValue(opacityProperty(), 0,
                    Interpolator.EASE_IN)
            )
        );
        tl.setOnFinished(e -> setVisible(false));
        tl.play();
    }
}

package fan.summer.api.content;

import com.toolbox.api.ToolPlugin;
import javafx.animation.*;
import javafx.geometry.Insets;
import javafx.scene.control.Label;
import javafx.scene.layout.Priority;
import javafx.scene.layout.StackPane;
import javafx.scene.layout.VBox;
import javafx.util.Duration;

import java.util.function.Consumer;

/**
 * Single card in the tool grid.
 * After clicking, callbacks onSelect, parent component decides to open detail panel or launch tool.
 */
public class ToolCard extends VBox {

    private final ToolPlugin plugin;

    public ToolCard(ToolPlugin plugin, Consumer<ToolPlugin> onSelect) {
        this.plugin = plugin;
        getStyleClass().add("tool-card");
        setSpacing(3);
        setPadding(new Insets(16, 14, 14, 14));

        // ── Icon ────────────────────────────────────────
        Label iconLabel = new Label(plugin.getIconText());
        iconLabel.setStyle("-fx-font-size: 18px;");

        StackPane iconWrap = new StackPane(iconLabel);
        iconWrap.getStyleClass().addAll("tool-icon-wrap", plugin.getIconStyle());
        iconWrap.setPrefSize(40, 40);
        iconWrap.setMinSize(40, 40);

        // ── Text ────────────────────────────────────────
        Label nameLabel = new Label(plugin.getName());
        nameLabel.getStyleClass().add("tool-name");
        nameLabel.setMaxWidth(Double.MAX_VALUE);

        Label descLabel = new Label(plugin.getDescription());
        descLabel.getStyleClass().add("tool-desc");
        descLabel.setWrapText(true);
        descLabel.setMaxWidth(Double.MAX_VALUE);
        VBox.setVgrow(descLabel, Priority.ALWAYS);

        // ── Tag ────────────────────────────────────────
        boolean isPlugin = !"builtin".equals(plugin.getType());
        Label tag = new Label(isPlugin ? "Plugin" : "Built-in");
        tag.getStyleClass().addAll("tool-tag", isPlugin ? "tool-tag-plugin" : "");

        getChildren().addAll(iconWrap, nameLabel, descLabel, tag);

        // ── Hover animation ─────────────────────────────────────
        ScaleTransition hoverIn  = new ScaleTransition(Duration.millis(150), this);
        ScaleTransition hoverOut = new ScaleTransition(Duration.millis(150), this);
        hoverIn.setToX(1.03); hoverIn.setToY(1.03);
        hoverOut.setToX(1.0); hoverOut.setToY(1.0);

        setOnMouseEntered(e -> { hoverOut.stop(); hoverIn.play(); });
        setOnMouseExited( e -> { hoverIn.stop(); hoverOut.play(); });

        // ── Click animation + callback ───────────────────────────────
        setOnMouseClicked(e -> {
            ScaleTransition click = new ScaleTransition(Duration.millis(100), this);
            click.setToX(0.97); click.setToY(0.97);
            click.setAutoReverse(true); click.setCycleCount(2);
            click.setOnFinished(ev -> onSelect.accept(plugin));
            click.play();
        });

        // ── Entry animation ─────────────────────────────────────
        setOpacity(0);
        setScaleX(0.94); setScaleY(0.94);
        setTranslateY(8);

        FadeTransition ft = new FadeTransition(Duration.millis(280), this);
        ft.setToValue(1);
        TranslateTransition tt = new TranslateTransition(Duration.millis(280), this);
        tt.setToY(0);
        ScaleTransition st = new ScaleTransition(Duration.millis(280), this);
        st.setToX(1); st.setToY(1);

        ParallelTransition entry = new ParallelTransition(ft, tt, st);
        entry.setInterpolator(new Interpolator() {
            @Override protected double curve(double t) {
                // Simple spring curve
                return 1 - Math.pow(1 - t, 3) * Math.cos(t * Math.PI * 2);
            }
        });
        // Delay set by caller, see ToolGrid
        entry.play();

        setCursor(javafx.scene.Cursor.HAND);
    }

    public ToolPlugin getPlugin() { return plugin; }
}

package fan.summer.api.content;

import fan.summer.api.SwissKitJPlugin;
import javafx.animation.FadeTransition;
import javafx.animation.ParallelTransition;
import javafx.animation.PauseTransition;
import javafx.animation.TranslateTransition;
import javafx.collections.ListChangeListener;
import javafx.collections.ObservableList;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Node;
import javafx.scene.control.Label;
import javafx.scene.control.ScrollPane;
import javafx.scene.control.TextField;
import javafx.scene.layout.*;
import javafx.util.Duration;

import java.util.List;
import java.util.function.Consumer;

/**
 * Main content area.
 * Contains: Search bar / Tool grid / Detail panel / Page transition animations.
 * Bind plugin data via setPlugins(ObservableList), auto-respond to add/remove.
 */
public class ContentArea extends BorderPane {

    // ── Sub-components ────────────────────────────────────────────
    private final TextField   searchField  = new TextField();
    private final FlowPane    toolGrid     = new FlowPane();
    private final DetailPanel detailPanel  = new DetailPanel();
    private final StackPane   pageStack    = new StackPane();
    private final ScrollPane  scrollPane;

    // ── State ──────────────────────────────────────────────
    private ObservableList<ToolPlugin> plugins;
    private String   currentCategory = "all";
    private String   currentQuery    = "";
    private Consumer<ToolPlugin> onLaunch;

    public ContentArea() {
        scrollPane = buildScrollPane();
        buildLayout();
        detailPanel.setOnLaunch(p -> { if (onLaunch != null) onLaunch.accept(p); });
    }

    // ── Public API ──────────────────────────────────────────

    public void setOnLaunch(Consumer<ToolPlugin> handler) { this.onLaunch = handler; }

    /** Bind plugin list, auto-refresh on add/remove */
    public void setPlugins(ObservableList<ToolPlugin> list) {
        this.plugins = list;
        list.addListener((ListChangeListener<ToolPlugin>) c -> refresh());
        refresh();
    }

    /** Switch category display */
    public void showCategory(String categoryId) {
        currentCategory = categoryId;
        searchField.clear();
        currentQuery = "";
        crossFadeTo(scrollPane);
        refresh();
        animateGridIn();
    }

    /** Switch to custom page (e.g. settings, plugin market) */
    public void showPage(Node page, String title) {
        crossFadeTo(page);
        detailPanel.hide();
    }

    /** Back to tool grid home */
    public void showToolGrid() {
        crossFadeTo(scrollPane);
    }

    // ── Layout build ──────────────────────────────────────────

    private void buildLayout() {
        // Search bar
        HBox searchBar = buildSearchBar();
        VBox top = new VBox(searchBar);
        top.setPadding(new Insets(12, 16, 0, 16));
        setTop(top);

        // Center: StackPane (switchable content) + Detail panel
        pageStack.getChildren().add(scrollPane);
        pageStack.setAlignment(Pos.TOP_LEFT);

        HBox center = new HBox(pageStack, detailPanel);
        HBox.setHgrow(pageStack, Priority.ALWAYS);
        setCenter(center);
    }

    private HBox buildSearchBar() {
        Label searchIcon = new Label("🔍");
        searchIcon.setStyle("-fx-font-size: 13px; -fx-text-fill: rgba(255,255,255,0.28);");

        searchField.getStyleClass().add("search-field");
        searchField.setPromptText("Search tools...");
        searchField.setMaxWidth(Double.MAX_VALUE);
        HBox.setHgrow(searchField, Priority.ALWAYS);
        searchField.textProperty().addListener((obs, oldVal, newVal) -> {
            currentQuery = newVal.trim().toLowerCase();
            refresh();
        });

        Label kbdHint = new Label("⌘K");
        kbdHint.setStyle(
            "-fx-font-size: 10px; -fx-text-fill: rgba(255,255,255,0.28);" +
            "-fx-background-color: rgba(255,255,255,0.06);" +
            "-fx-border-color: rgba(255,255,255,0.10); -fx-border-width: 1;" +
            "-fx-border-radius: 4; -fx-background-radius: 4;" +
            "-fx-padding: 1 5 1 5; -fx-font-family: 'SF Mono','Consolas',monospace;"
        );

        HBox bar = new HBox(10, searchIcon, searchField, kbdHint);
        bar.getStyleClass().add("search-bar");
        bar.setAlignment(Pos.CENTER_LEFT);
        bar.setPrefHeight(38);
        return bar;
