    private final Label   typeVal     = new Label();
    private final Label   categoryVal = new Label();
    private final Button  launchBtn   = new Button("Launch Tool");
    private final Button  closeBtn    = new Button("✕");

    private Consumer<ToolPlugin> onLaunch;
    private ToolPlugin currentPlugin;
    private boolean    panelOpen = false;

    public DetailPanel() {
        getStyleClass().add("detail-panel");
        setPrefWidth(0);   // Initially collapsed
        setMinWidth(0);
        setMaxWidth(PANEL_WIDTH);

        buildUI();
        setVisible(false);
    }

    // ── Public API ──────────────────────────────────────────

    public void setOnLaunch(Consumer<ToolPlugin> handler) {
        this.onLaunch = handler;
    }

    /** Show plugin details, auto-slides in on first call */
    public void show(ToolPlugin plugin) {
        this.currentPlugin = plugin;
        fillData(plugin);
        if (!panelOpen) slideIn();
    }

    /** Slide out and hide */
    public void hide() {
        if (panelOpen) slideOut();
    }

    public boolean isPanelOpen() { return panelOpen; }

    // ── Build UI ───────────────────────────────────────────

    private void buildUI() {
        iconLabel.setStyle("-fx-font-size: 26px;");
        iconWrap.setPrefSize(56, 56);
        iconWrap.setMinSize(56, 56);
        iconWrap.getStyleClass().add("tool-icon-wrap");
        iconWrap.getStyleClass().add("ic-blue");

        nameLabel.getStyleClass().add("tool-name");
        nameLabel.setStyle("-fx-font-size: 16px;");

        metaLabel.getStyleClass().add("status-text");
        metaLabel.setStyle("-fx-font-size: 11px;");

        descLabel.getStyleClass().add("tool-desc");
        descLabel.setWrapText(true);
        descLabel.setStyle("-fx-font-size: 12.5px;");

        launchBtn.getStyleClass().add("detail-launch-btn");
        launchBtn.setMaxWidth(Double.MAX_VALUE);
        launchBtn.setOnAction(e -> {
            if (onLaunch != null && currentPlugin != null)
                onLaunch.accept(currentPlugin);
        });

        closeBtn.setStyle(
            "-fx-background-color: transparent; -fx-border-width: 0;" +
            "-fx-text-fill: rgba(255,255,255,0.35); -fx-cursor: hand; -fx-font-size: 14px;"
        );
        closeBtn.setOnAction(e -> hide());
        closeBtn.setOnMouseEntered(e ->
            closeBtn.setStyle(closeBtn.getStyle() + "-fx-text-fill: rgba(255,255,255,0.85);"));
        closeBtn.setOnMouseExited(e ->
            closeBtn.setStyle(closeBtn.getStyle().replace("-fx-text-fill: rgba(255,255,255,0.85);", "")));

        HBox topRow = new HBox(closeBtn);
        topRow.setAlignment(Pos.CENTER_RIGHT);

        Separator sep = new Separator();
        sep.setStyle("-fx-border-color: rgba(255,255,255,0.10); -fx-padding: 8 0 8 0;");

        // Property rows
        VBox propsBox = new VBox(6,
            propRow("Version",   versionVal),
            propRow("Type",   typeVal),
            propRow("Category",   categoryVal)
        );

        setSpacing(10);
        setPadding(new Insets(16));
        getChildren().addAll(
            topRow, iconWrap, nameLabel, metaLabel, descLabel,
            launchBtn, sep, propsBox
        );
    }

    private HBox propRow(String key, Label valLabel) {
        Label keyLabel = new Label(key);
        keyLabel.setStyle("-fx-text-fill: rgba(255,255,255,0.30); -fx-font-size: 12px;");
        valLabel.setStyle("-fx-text-fill: rgba(255,255,255,0.55); -fx-font-size: 12px; " +
                          "-fx-font-family: 'SF Mono','Consolas',monospace;");
        Region spacer = new Region();
        HBox.setHgrow(spacer, Priority.ALWAYS);
        return new HBox(keyLabel, spacer, valLabel);
    }

    // ── Data fill ─────────────────────────────────────────

    private void fillData(ToolPlugin p) {
        iconLabel.setText(p.getIconText());
        iconWrap.getStyleClass().removeIf(c -> c.startsWith("ic-"));
        iconWrap.getStyleClass().add(p.getIconStyle());

        nameLabel.setText(p.getName());
        metaLabel.setText("v" + p.getVersion() + " · " + p.getType());
        descLabel.setText(p.getDescription());

        versionVal.setText(p.getVersion());
        typeVal.setText(p.getType());
        categoryVal.setText(categoryName(p.getCategory()));
    }

    private String categoryName(String cat) {
        return switch (cat) {
            case "dev"   -> "Developer Tools";
            case "text"  -> "Text Processing";
            case "image" -> "Image Processing";
            case "net"   -> "Network Tools";
            default      -> cat;
        };
    }

    // ── Slide in / out animations ─────────────────────────

    private void slideIn() {
        panelOpen = true;
        setVisible(true);

        Timeline tl = new Timeline(
            new KeyFrame(Duration.ZERO,
                new KeyValue(prefWidthProperty(), 0),
                new KeyValue(opacityProperty(), 0)
            ),
            new KeyFrame(Duration.millis(300),
                new KeyValue(prefWidthProperty(), PANEL_WIDTH,
                    Interpolator.SPLINE(0.4, 0, 0.2, 1)),
                new KeyValue(opacityProperty(), 1,
                    Interpolator.EASE_OUT)
            )
        );
        tl.play();
    }

    private void slideOut() {
        panelOpen = false;
        Timeline tl = new Timeline(
            new KeyFrame(Duration.ZERO,
                new KeyValue(prefWidthProperty(), PANEL_WIDTH),
                new KeyValue(opacityProperty(), 1)
            ),
            new KeyFrame(Duration.millis(250),
                new KeyValue(prefWidthProperty(), 0,
                    Interpolator.SPLINE(0.4, 0, 0.2, 1)),
                new KeyValue(opacityProperty(), 0,
                    Interpolator.EASE_IN)
            )
        );
        tl.setOnFinished(e -> setVisible(false));
        tl.play();
    }
}

package fan.summer.api.content;

import fan.summer.api.SwissKitJPlugin;
import javafx.animation.*;
import javafx.geometry.Insets;
import javafx.scene.control.Label;
import javafx.scene.layout.Priority;
import javafx.scene.layout.StackPane;
import javafx.scene.layout.VBox;
import javafx.util.Duration;

import java.util.function.Consumer;

/**
 * Single card in the tool grid.
 * After clicking, callbacks onSelect, parent component decides to open detail panel or launch tool.
 */
public class ToolCard extends VBox {

    private final ToolPlugin plugin;

    public ToolCard(ToolPlugin plugin, Consumer<ToolPlugin> onSelect) {
        this.plugin = plugin;
        getStyleClass().add("tool-card");
        setSpacing(3);
        setPadding(new Insets(16, 14, 14, 14));

        // ── Icon ────────────────────────────────────────
        Label iconLabel = new Label(plugin.getIconText());
        iconLabel.setStyle("-fx-font-size: 18px;");

        StackPane iconWrap = new StackPane(iconLabel);
        iconWrap.getStyleClass().addAll("tool-icon-wrap", plugin.getIconStyle());
        iconWrap.setPrefSize(40, 40);
        iconWrap.setMinSize(40, 40);

        // ── Text ────────────────────────────────────────
        Label nameLabel = new Label(plugin.getName());
        nameLabel.getStyleClass().add("tool-name");
        nameLabel.setMaxWidth(Double.MAX_VALUE);

        Label descLabel = new Label(plugin.getDescription());
        descLabel.getStyleClass().add("tool-desc");
        descLabel.setWrapText(true);
        descLabel.setMaxWidth(Double.MAX_VALUE);
        VBox.setVgrow(descLabel, Priority.ALWAYS);

        // ── Tag ────────────────────────────────────────
        boolean isPlugin = !"builtin".equals(plugin.getType());
        Label tag = new Label(isPlugin ? "Plugin" : "Built-in");
        tag.getStyleClass().addAll("tool-tag", isPlugin ? "tool-tag-plugin" : "");

        getChildren().addAll(iconWrap, nameLabel, descLabel, tag);

        // ── Hover animation ─────────────────────────────────────
        ScaleTransition hoverIn  = new ScaleTransition(Duration.millis(150), this);
        ScaleTransition hoverOut = new ScaleTransition(Duration.millis(150), this);
        hoverIn.setToX(1.03); hoverIn.setToY(1.03);
        hoverOut.setToX(1.0); hoverOut.setToY(1.0);

        setOnMouseEntered(e -> { hoverOut.stop(); hoverIn.play(); });
        setOnMouseExited( e -> { hoverIn.stop(); hoverOut.play(); });

        // ── Click animation + callback ───────────────────────────────
        setOnMouseClicked(e -> {
            ScaleTransition click = new ScaleTransition(Duration.millis(100), this);
            click.setToX(0.97); click.setToY(0.97);
            click.setAutoReverse(true); click.setCycleCount(2);
            click.setOnFinished(ev -> onSelect.accept(plugin));
            click.play();
        });

        // ── Entry animation ─────────────────────────────────────
        setOpacity(0);
        setScaleX(0.94); setScaleY(0.94);
        setTranslateY(8);

        FadeTransition ft = new FadeTransition(Duration.millis(280), this);
        ft.setToValue(1);
        TranslateTransition tt = new TranslateTransition(Duration.millis(280), this);
        tt.setToY(0);
        ScaleTransition st = new ScaleTransition(Duration.millis(280), this);
        st.setToX(1); st.setToY(1);

        ParallelTransition entry = new ParallelTransition(ft, tt, st);
        entry.setInterpolator(new Interpolator() {
            @Override protected double curve(double t) {
                // Simple spring curve
                return 1 - Math.pow(1 - t, 3) * Math.cos(t * Math.PI * 2);
            }
        });
        // Delay set by caller, see ToolGrid
        entry.play();

        setCursor(javafx.scene.Cursor.HAND);
    }

    public ToolPlugin getPlugin() { return plugin; }
}

