package fan.summer.api;

import fan.summer.plugin.PluginLoader;
import fan.summer.plugin.PluginRegistry;
import fan.summer.api.content.ContentArea;
import fan.summer.api.sidebar.Sidebar;
import fan.summer.api.titlebar.TitleBar;
import fan.summer.api.SwissKitJPlugin;
import javafx.animation.*;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.control.Label;
import javafx.scene.layout.*;
import javafx.scene.paint.Color;
import javafx.scene.shape.Circle;
import javafx.scene.shape.Rectangle;
import javafx.stage.Stage;
import javafx.util.Duration;

import java.time.LocalTime;
import java.time.format.DateTimeFormatter;

/**
 * Root node of the main window.
 * Assembles TitleBar / Sidebar / ContentArea / StatusBar,
 * and holds the lifecycle for PluginLoader and PluginRegistry.
 */
public class MainWindow extends StackPane {

    private final Stage        stage;
    private final PluginLoader loader;
    private final PluginRegistry registry;

    private final TitleBar    titleBar;
    private final Sidebar     sidebar;
    private final ContentArea contentArea;

    // Status bar labels
    private final Label statusToolCount    = statusText("0 tools");
    private final Label statusPluginCount  = statusText("0 plugins");
    private final Label clockLabel         = statusText("");

    private Timeline clockTimeline;

    public MainWindow(Stage stage, PluginLoader loader, PluginRegistry registry) {
        this.stage    = stage;
        this.loader   = loader;
        this.registry = registry;

        titleBar    = new TitleBar(stage, this::openSettings);
        sidebar     = new Sidebar();
        contentArea = new ContentArea();

        buildScene();
        wireEvents();
        startClock();
        playEntryAnimation();
    }

    // ── Build scene graph ────────────────────────────────

    private void buildScene() {
        // Background orb layer (bottom layer)
        Pane orbLayer = buildOrbLayer();

        // Main window glass panel
        BorderPane windowPane = new BorderPane();
        windowPane.getStyleClass().add("app-root");
        windowPane.setStyle(
            "-fx-background-color: rgba(13,14,17,0.72);" +
            "-fx-background-radius: 20;" +
            "-fx-border-radius: 20;" +
            "-fx-border-color: rgba(255,255,255,0.10);" +
            "-fx-border-width: 1;" +
            "-fx-effect: dropshadow(gaussian, rgba(0,0,0,0.6), 60, 0, 0, 20);"
        );

        // Title bar
        windowPane.setTop(titleBar);

        // Body: sidebar + content area
        HBox body = new HBox(sidebar, contentArea);
        HBox.setHgrow(contentArea, Priority.ALWAYS);
        windowPane.setCenter(body);

        // Status bar
        windowPane.setBottom(buildStatusBar());

        // Top highlight border (glass thickness simulation)
        Rectangle topHighlight = new Rectangle();
        topHighlight.setMouseTransparent(true);
        topHighlight.setStyle(
            "-fx-fill: transparent;" +
            "-fx-stroke: rgba(255,255,255,0.12);" +
            "-fx-stroke-width: 1;" +
            "-fx-arc-width: 40; -fx-arc-height: 40;"
        );
        topHighlight.widthProperty().bind(widthProperty());
        topHighlight.heightProperty().bind(heightProperty());

        getChildren().addAll(orbLayer, windowPane, topHighlight);
        setAlignment(windowPane, Pos.CENTER);
        setAlignment(topHighlight, Pos.CENTER);
    }

    // ── Background orbs ───────────────────────────────────

    private Pane buildOrbLayer() {
        Pane layer = new Pane();
        layer.setMouseTransparent(true);
        layer.setStyle("-fx-background-color: #0d0e11;");

        // Three colored Gaussian blur orbs
        layer.getChildren().addAll(
            orb(480, "#3b5bdb", -80, -120, 0),
            orb(360, "#7048e8",  -60, 200,  -6000),
            orb(300, "#1c7ed6",  300, 400, -12000)
        );
        return layer;
    }

    private StackPane orb(double size, String color, double x, double y, double animDelay) {
        Circle c = new Circle(size / 2,
            Color.web(color, 0.28));
        c.setEffect(new javafx.scene.effect.GaussianBlur(60));

        StackPane wrap = new StackPane(c);
        wrap.setTranslateX(x);
        wrap.setTranslateY(y);
        wrap.setMouseTransparent(true);

        // Floating animation
        TranslateTransition drift = new TranslateTransition(Duration.millis(18000), wrap);
        drift.setByX(30); drift.setByY(20);
        drift.setAutoReverse(true);
        drift.setCycleCount(Animation.INDEFINITE);
        drift.setDelay(Duration.millis(Math.abs(animDelay)));
        drift.setInterpolator(Interpolator.EASE_BOTH);
        drift.play();

        ScaleTransition breathe = new ScaleTransition(Duration.millis(12000), wrap);
        breathe.setFromX(1.0); breathe.setFromY(1.0);
        breathe.setToX(1.08);  breathe.setToY(1.08);
        breathe.setAutoReverse(true);
        breathe.setCycleCount(Animation.INDEFINITE);
        breathe.setInterpolator(Interpolator.EASE_BOTH);
        breathe.play();

        return wrap;
    }

    // ── Status bar ───────────────────────────────────────

    private HBox buildStatusBar() {
        // Activity indicator dot
        Circle dot = new Circle(3, Color.web("#4cd97b"));
        dot.setEffect(new javafx.scene.effect.Glow(0.8));
        FadeTransition pulse = new FadeTransition(Duration.millis(2500), dot);
        pulse.setFromValue(1.0); pulse.setToValue(0.4);
        pulse.setAutoReverse(true); pulse.setCycleCount(Animation.INDEFINITE);
        pulse.play();

        Label sep = statusText("·");
        sep.setStyle("-fx-text-fill: rgba(255,255,255,0.15); -fx-font-size: 11px;");

        Region spacer = new Region();
        HBox.setHgrow(spacer, Priority.ALWAYS);

        HBox bar = new HBox(10);
        bar.getStyleClass().add("statusbar");
        bar.setAlignment(Pos.CENTER_LEFT);
        bar.setPadding(new Insets(0, 16, 0, 16));
        bar.getChildren().addAll(dot, statusToolCount, sep, statusPluginCount, spacer, clockLabel);
        return bar;
    }

    private Label statusText(String text) {
        Label l = new Label(text);
        l.getStyleClass().add("status-text");
        return l;
    }

    // ── Event wiring ─────────────────────────────────────

    private void wireEvents() {
        // Bind plugin list to content area
        contentArea.setPlugins(registry.getPlugins());

        // Sidebar category switch → content area filter
        sidebar.setOnCategorySelect(categoryId -> {
            contentArea.showCategory(categoryId);
        });

        // Settings (standalone, not part of nav state machine)
        sidebar.setOnSettingsSelect(this::openSettings);

        // Plugin list change → update status bar
        registry.getPlugins().addListener(
            (javafx.collections.ListChangeListener<SwissKitJPlugin>) c -> {
                int total   = registry.getPlugins().size();
                int plugins = (int) registry.getPlugins().stream()
                    .filter(p -> !"builtin".equals(p.getType())).count();
                statusToolCount.setText(total + " tools");
                statusPluginCount.setText(plugins + " plugins");
                sidebar.updateBadge("plugins", plugins);
            }
        );

        // Tool launch callback
        contentArea.setOnLaunch(plugin -> {
            registry.activate(plugin);
            contentArea.showPage(plugin.createView(), plugin.getName());
        });
    }

    // ── Settings page ────────────────────────────────────

    private void openSettings() {
        Label placeholder = new Label("⚙️  Settings Panel\n(Coming soon)");
        placeholder.setStyle(
            "-fx-text-fill: rgba(255,255,255,0.40); -fx-font-size: 16px;" +
            "-fx-alignment: center; -fx-text-alignment: center;"
        );
        StackPane page = new StackPane(placeholder);
        page.setStyle("-fx-background-color: transparent;");
        contentArea.showPage(page, "Settings");
    }

    // ── Entry animation ──────────────────────────────────

    private void playEntryAnimation() {
        // Get windowPane (second child node)
        javafx.scene.Node windowPane = getChildren().get(1);
        windowPane.setOpacity(0);
        windowPane.setScaleX(0.94);
        windowPane.setScaleY(0.94);
        windowPane.setTranslateY(16);

        FadeTransition ft = new FadeTransition(Duration.millis(500), windowPane);
        ft.setToValue(1);

        ScaleTransition st = new ScaleTransition(Duration.millis(500), windowPane);
        st.setToX(1); st.setToY(1);
        st.setInterpolator(Interpolator.SPLINE(0.34, 0.9, 0.64, 1.0));

        TranslateTransition tt = new TranslateTransition(Duration.millis(500), windowPane);
        tt.setToY(0);
        tt.setInterpolator(Interpolator.SPLINE(0.34, 0.9, 0.64, 1.0));

        new ParallelTransition(ft, st, tt).play();
    }

    // ── Clock ────────────────────────────────────────────

    private void startClock() {
        DateTimeFormatter fmt = DateTimeFormatter.ofPattern("HH:mm:ss");
        clockTimeline = new Timeline(new KeyFrame(Duration.seconds(1), e ->
            clockLabel.setText(LocalTime.now().format(fmt))
        ));
        clockTimeline.setCycleCount(Animation.INDEFINITE);
        clockTimeline.play();
        clockLabel.setText(LocalTime.now().format(fmt)); // Initial display
    }

    /** Called on application exit to clean up resources */
    public void shutdown() {
        if (clockTimeline != null) clockTimeline.stop();
        loader.stop();
    }
}

package fan.summer.api.content;

import fan.summer.api.SwissKitJPlugin;
import javafx.animation.FadeTransition;
import javafx.animation.ParallelTransition;
import javafx.animation.PauseTransition;
import javafx.animation.TranslateTransition;
import javafx.collections.ListChangeListener;
import javafx.collections.ObservableList;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Node;
import javafx.scene.control.Label;
import javafx.scene.control.ScrollPane;
import javafx.scene.control.TextField;
import javafx.scene.layout.*;
import javafx.util.Duration;

import java.util.List;
import java.util.function.Consumer;

/**
 * Main content area.
 * Contains: Search bar / Tool grid / Detail panel / Page transition animations.
 * Bind plugin data via setPlugins(ObservableList), auto-respond to add/remove.
 */
public class ContentArea extends BorderPane {

    // ── Sub-components ────────────────────────────────────────────
    private final TextField   searchField  = new TextField();
    private final FlowPane    toolGrid     = new FlowPane();
    private final DetailPanel detailPanel  = new DetailPanel();
    private final StackPane   pageStack    = new StackPane();
    private final ScrollPane  scrollPane;

    // ── State ──────────────────────────────────────────────
    private ObservableList<SwissKitJPlugin> plugins;
    private String   currentCategory = "all";
    private String   currentQuery    = "";
    private Consumer<SwissKitJPlugin> onLaunch;

    public ContentArea() {
        scrollPane = buildScrollPane();
        buildLayout();
        detailPanel.setOnLaunch(p -> { if (onLaunch != null) onLaunch.accept(p); });
    }

    // ── Public API ──────────────────────────────────────────

    public void setOnLaunch(Consumer<SwissKitJPlugin> handler) { this.onLaunch = handler; }

    /** Bind plugin list, auto-refresh on add/remove */
    public void setPlugins(ObservableList<SwissKitJPlugin> list) {
        this.plugins = list;
        list.addListener((ListChangeListener<SwissKitJPlugin>) c -> refresh());
        refresh();
    }

    /** Switch category display */
    public void showCategory(String categoryId) {
        currentCategory = categoryId;
        searchField.clear();
        currentQuery = "";
        crossFadeTo(scrollPane);
        refresh();
        animateGridIn();
    }

    /** Switch to custom page (e.g. settings, plugin market) */
    public void showPage(Node page, String title) {
        crossFadeTo(page);
        detailPanel.hide();
    }

    /** Back to tool grid home */
    public void showToolGrid() {
        crossFadeTo(scrollPane);
    }

    // ── Layout build ──────────────────────────────────────────

    private void buildLayout() {
        // Search bar
        HBox searchBar = buildSearchBar();
        VBox top = new VBox(searchBar);
        top.setPadding(new Insets(12, 16, 0, 16));
        setTop(top);

        // Center: StackPane (switchable content) + Detail panel
        pageStack.getChildren().add(scrollPane);
        pageStack.setAlignment(Pos.TOP_LEFT);

        HBox center = new HBox(pageStack, detailPanel);
        HBox.setHgrow(pageStack, Priority.ALWAYS);
        setCenter(center);
    }

    private HBox buildSearchBar() {
        Label searchIcon = new Label("🔍");
        searchIcon.setStyle("-fx-font-size: 13px; -fx-text-fill: rgba(255,255,255,0.28);");

        searchField.getStyleClass().add("search-field");
        searchField.setPromptText("Search tools...");
        searchField.setMaxWidth(Double.MAX_VALUE);
        HBox.setHgrow(searchField, Priority.ALWAYS);
        searchField.textProperty().addListener((obs, oldVal, newVal) -> {
            currentQuery = newVal.trim().toLowerCase();
            refresh();
        });

        Label kbdHint = new Label("⌘K");
        kbdHint.setStyle(
            "-fx-font-size: 10px; -fx-text-fill: rgba(255,255,255,0.28);" +
            "-fx-background-color: rgba(255,255,255,0.06);" +
            "-fx-border-color: rgba(255,255,255,0.10); -fx-border-width: 1;" +
            "-fx-border-radius: 4; -fx-background-radius: 4;" +
            "-fx-padding: 1 5 1 5; -fx-font-family: 'SF Mono','Consolas',monospace;"
        );

        HBox bar = new HBox(10, searchIcon, searchField, kbdHint);
        bar.getStyleClass().add("search-bar");
        bar.setAlignment(Pos.CENTER_LEFT);
        bar.setPrefHeight(38);
        return bar;
    }

    private ScrollPane buildScrollPane() {
        // Tool grid
        toolGrid.setHgap(10);
        toolGrid.setVgap(10);
        toolGrid.setPadding(new Insets(16));
        toolGrid.setPrefWrapLength(600);

        VBox wrapper = new VBox(
            sectionHeader("FREQUENT", ""),
            toolGrid
        );
        wrapper.setPadding(new Insets(8, 16, 16, 16));
        wrapper.setSpacing(0);

        ScrollPane sp = new ScrollPane(wrapper);
        sp.getStyleClass().add("content-scroll");
        sp.setFitToWidth(true);
        sp.setHbarPolicy(ScrollPane.ScrollBarPolicy.NEVER);
        sp.setVbarPolicy(ScrollPane.ScrollBarPolicy.AS_NEEDED);
        sp.setStyle("-fx-background-color: transparent; -fx-background: transparent;");
        return sp;
    }

    // ── Grid refresh ──────────────────────────────────────────

    private void refresh() {
        if (plugins == null) return;

        List<SwissKitJPlugin> filtered = plugins.stream()
            .filter(this::matchesCategory)
            .filter(this::matchesQuery)
            .toList();

        toolGrid.getChildren().clear();

        for (int i = 0; i < filtered.size(); i++) {
            SwissKitJPlugin p = filtered.get(i);
            ToolCard card = new ToolCard(p, this::onCardSelect);
            card.setPrefWidth(152);
            card.setPrefHeight(130);

            // Staggered entry delay
            int delay = i * 35;
            card.setOpacity(0);
            PauseTransition pause = new PauseTransition(Duration.millis(delay));
            pause.setOnFinished(e -> {
                FadeTransition ft = new FadeTransition(Duration.millis(240), card);
                ft.setFromValue(0); ft.setToValue(1);
                TranslateTransition tt = new TranslateTransition(Duration.millis(240), card);
                tt.setFromY(10); tt.setToY(0);
                new ParallelTransition(ft, tt).play();
            });
            pause.play();

            toolGrid.getChildren().add(card);
        }

        // Empty state message
        if (filtered.isEmpty()) {
            Label empty = new Label("No matching tools found");
            empty.setStyle("-fx-text-fill: rgba(255,255,255,0.28); -fx-font-size: 13px;");
            empty.setPadding(new Insets(40, 0, 0, 0));
            toolGrid.getChildren().add(empty);
        }
    }

    // ── Filter logic ──────────────────────────────────────────

    private boolean matchesCategory(SwissKitJPlugin p) {
        return switch (currentCategory) {
            case "all"     -> true;
            case "plugins" -> !"builtin".equals(p.getType());
            case "fav"     -> false; // TODO: integrate favorites persistence
            default        -> p.getCategory().equalsIgnoreCase(currentCategory);
        };
    }

    private boolean matchesQuery(SwissKitJPlugin p) {
        if (currentQuery.isEmpty()) return true;
        return p.getName().toLowerCase().contains(currentQuery)
            || p.getDescription().toLowerCase().contains(currentQuery);
    }

    // ── Card selection ──────────────────────────────────────────

    private void onCardSelect(SwissKitJPlugin plugin) {
        detailPanel.show(plugin);
    }

    // ── Page transition animation (cross-fade) ──────────────────────

    private void crossFadeTo(Node next) {
        Node current = pageStack.getChildren().isEmpty()
            ? null : pageStack.getChildren().get(0);

        next.setOpacity(0);
        if (!pageStack.getChildren().contains(next))
            pageStack.getChildren().add(next);
        next.toFront();

        FadeTransition fadeIn = new FadeTransition(Duration.millis(220), next);
        fadeIn.setToValue(1);

        if (current != null && current != next) {
            FadeTransition fadeOut = new FadeTransition(Duration.millis(180), current);
            fadeOut.setToValue(0);
            Node finalCurrent = current;
            fadeOut.setOnFinished(e -> pageStack.getChildren().remove(finalCurrent));
            new ParallelTransition(fadeOut, fadeIn).play();
        } else {
            fadeIn.play();
        }
    }

    private void animateGridIn() {
        // Grid slides in from slightly below
        TranslateTransition tt = new TranslateTransition(Duration.millis(280), toolGrid);
        tt.setFromY(12); tt.setToY(0);
        FadeTransition ft = new FadeTransition(Duration.millis(280), toolGrid);
        ft.setFromValue(0.4); ft.setToValue(1);
        new ParallelTransition(tt, ft).play();
    }

    // ── Helper node factory ──────────────────────────────────────

    private HBox sectionHeader(String title, String action) {
        Label titleLabel = new Label(title.toUpperCase());
        titleLabel.getStyleClass().add("section-title");

        Region spacer = new Region();
        HBox.setHgrow(spacer, Priority.ALWAYS);

        HBox row = new HBox(titleLabel, spacer);
        if (!action.isEmpty()) {
            Label actionLabel = new Label(action);
            actionLabel.setStyle("-fx-text-fill: #5b8cf7; -fx-font-size: 12px; -fx-cursor: hand;");
            row.getChildren().add(actionLabel);
        }
        row.setAlignment(Pos.CENTER_LEFT);
        row.setPadding(new Insets(8, 0, 10, 0));
        return row;
    }
}

package fan.summer.api.content;

import fan.summer.api.SwissKitJPlugin;
import javafx.animation.Interpolator;
import javafx.animation.KeyFrame;
import javafx.animation.KeyValue;
import javafx.animation.Timeline;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.control.Button;
import javafx.scene.control.Label;
import javafx.scene.control.Separator;
import javafx.scene.layout.*;
import javafx.util.Duration;

import java.util.function.Consumer;

/**
 * Tool detail panel, slides in from right.
 * show(plugin) fills data and expands; hide() collapses.
 */
public class DetailPanel extends VBox {

    private static final double PANEL_WIDTH = 260;

    private final Label   iconLabel   = new Label();
    private final StackPane iconWrap  = new StackPane(iconLabel);
    private final Label   nameLabel   = new Label();
    private final Label   metaLabel   = new Label();
    private final Label   descLabel   = new Label();
    private final Label   versionVal  = new Label();
    private final Label   typeVal     = new Label();
    private final Label   categoryVal = new Label();
    private final Button  launchBtn   = new Button("Launch Tool");
    private final Button  closeBtn    = new Button("✕");

    private Consumer<SwissKitJPlugin> onLaunch;
    private SwissKitJPlugin currentPlugin;
    private boolean    panelOpen = false;

    public DetailPanel() {
        getStyleClass().add("detail-panel");
        setPrefWidth(0);   // Initially collapsed
        setMinWidth(0);
        setMaxWidth(PANEL_WIDTH);

        buildUI();
        setVisible(false);
    }

    // ── Public API ──────────────────────────────────────────

    public void setOnLaunch(Consumer<SwissKitJPlugin> handler) {
        this.onLaunch = handler;
    }

    /** Show plugin details, auto-slides in on first call */
    public void show(SwissKitJPlugin plugin) {
        this.currentPlugin = plugin;
        fillData(plugin);
        if (!panelOpen) slideIn();
    }

    /** Slide out and hide */
    public void hide() {
        if (panelOpen) slideOut();
    }

    public boolean isPanelOpen() { return panelOpen; }

    // ── Build UI ───────────────────────────────────────────

    private void buildUI() {
        iconLabel.setStyle("-fx-font-size: 26px;");
        iconWrap.setPrefSize(56, 56);
        iconWrap.setMinSize(56, 56);
        iconWrap.getStyleClass().add("tool-icon-wrap");
        iconWrap.getStyleClass().add("ic-blue");

        nameLabel.getStyleClass().add("tool-name");
        nameLabel.setStyle("-fx-font-size: 16px;");

        metaLabel.getStyleClass().add("status-text");
        metaLabel.setStyle("-fx-font-size: 11px;");

        descLabel.getStyleClass().add("tool-desc");
        descLabel.setWrapText(true);
        descLabel.setStyle("-fx-font-size: 12.5px;");

        launchBtn.getStyleClass().add("detail-launch-btn");
        launchBtn.setMaxWidth(Double.MAX_VALUE);
        launchBtn.setOnAction(e -> {
            if (onLaunch != null && currentPlugin != null)
                onLaunch.accept(currentPlugin);
        });

        closeBtn.setStyle(
            "-fx-background-color: transparent; -fx-border-width: 0;" +
            "-fx-text-fill: rgba(255,255,255,0.35); -fx-cursor: hand; -fx-font-size: 14px;"
        );
        closeBtn.setOnAction(e -> hide());
        closeBtn.setOnMouseEntered(e ->
            closeBtn.setStyle(closeBtn.getStyle() + "-fx-text-fill: rgba(255,255,255,0.85);"));
        closeBtn.setOnMouseExited(e ->
            closeBtn.setStyle(closeBtn.getStyle().replace("-fx-text-fill: rgba(255,255,255,0.85);", "")));

        HBox topRow = new HBox(closeBtn);
        topRow.setAlignment(Pos.CENTER_RIGHT);

        Separator sep = new Separator();
        sep.setStyle("-fx-border-color: rgba(255,255,255,0.10); -fx-padding: 8 0 8 0;");

        // Property rows
        VBox propsBox = new VBox(6,
            propRow("Version",   versionVal),
            propRow("Type",   typeVal),
            propRow("Category",   categoryVal)
        );

        setSpacing(10);
        setPadding(new Insets(16));
        getChildren().addAll(
            topRow, iconWrap, nameLabel, metaLabel, descLabel,
            launchBtn, sep, propsBox
        );
    }

    private HBox propRow(String key, Label valLabel) {
        Label keyLabel = new Label(key);
        keyLabel.setStyle("-fx-text-fill: rgba(255,255,255,0.30); -fx-font-size: 12px;");
        valLabel.setStyle("-fx-text-fill: rgba(255,255,255,0.55); -fx-font-size: 12px; " +
                          "-fx-font-family: 'SF Mono','Consolas',monospace;");
        Region spacer = new Region();
        HBox.setHgrow(spacer, Priority.ALWAYS);
        return new HBox(keyLabel, spacer, valLabel);
    }

    // ── Data fill ─────────────────────────────────────────

    private void fillData(SwissKitJPlugin p) {
        iconLabel.setText(p.getIconText());
        iconWrap.getStyleClass().removeIf(c -> c.startsWith("ic-"));
        iconWrap.getStyleClass().add(p.getIconStyle());

        nameLabel.setText(p.getName());
        metaLabel.setText("v" + p.getVersion() + " · " + p.getType());
        descLabel.setText(p.getDescription());

        versionVal.setText(p.getVersion());
        typeVal.setText(p.getType());
        categoryVal.setText(categoryName(p.getCategory()));
    }

    private String categoryName(String cat) {
        return switch (cat) {
            case "dev"   -> "Developer Tools";
            case "text"  -> "Text Processing";
            case "image" -> "Image Processing";
            case "net"   -> "Network Tools";
            default      -> cat;
        };
    }

    // ── Slide in / out animations ─────────────────────────

    private void slideIn() {
        panelOpen = true;
        setVisible(true);

        Timeline tl = new Timeline(
            new KeyFrame(Duration.ZERO,
                new KeyValue(prefWidthProperty(), 0),
                new KeyValue(opacityProperty(), 0)
            ),
            new KeyFrame(Duration.millis(300),
                new KeyValue(prefWidthProperty(), PANEL_WIDTH,
                    Interpolator.SPLINE(0.4, 0, 0.2, 1)),
                new KeyValue(opacityProperty(), 1,
                    Interpolator.EASE_OUT)
            )
        );
        tl.play();
    }

    private void slideOut() {
        panelOpen = false;
        Timeline tl = new Timeline(
            new KeyFrame(Duration.ZERO,
                new KeyValue(prefWidthProperty(), PANEL_WIDTH),
                new KeyValue(opacityProperty(), 1)
            ),
            new KeyFrame(Duration.millis(250),
                new KeyValue(prefWidthProperty(), 0,
                    Interpolator.SPLINE(0.4, 0, 0.2, 1)),
                new KeyValue(opacityProperty(), 0,
                    Interpolator.EASE_IN)
            )
        );
        tl.setOnFinished(e -> setVisible(false));
        tl.play();
    }
}

package fan.summer.api.content;

import fan.summer.api.SwissKitJPlugin;
import javafx.animation.*;
import javafx.geometry.Insets;
import javafx.scene.control.Label;
import javafx.scene.layout.Priority;
import javafx.scene.layout.StackPane;
import javafx.scene.layout.VBox;
import javafx.util.Duration;

import java.util.function.Consumer;

/**
 * Single card in the tool grid.
 * After clicking, callbacks onSelect, parent component decides to open detail panel or launch tool.
 */
public class ToolCard extends VBox {

    private final SwissKitJPlugin plugin;

    public ToolCard(SwissKitJPlugin plugin, Consumer<SwissKitJPlugin> onSelect) {
        this.plugin = plugin;
        getStyleClass().add("tool-card");
        setSpacing(3);
        setPadding(new Insets(16, 14, 14, 14));

        // ── Icon ────────────────────────────────────────
        Label iconLabel = new Label(plugin.getIconText());
        iconLabel.setStyle("-fx-font-size: 18px;");

        StackPane iconWrap = new StackPane(iconLabel);
        iconWrap.getStyleClass().addAll("tool-icon-wrap", plugin.getIconStyle());
        iconWrap.setPrefSize(40, 40);
        iconWrap.setMinSize(40, 40);

        // ── Text ────────────────────────────────────────
        Label nameLabel = new Label(plugin.getName());
        nameLabel.getStyleClass().add("tool-name");
        nameLabel.setMaxWidth(Double.MAX_VALUE);

        Label descLabel = new Label(plugin.getDescription());
        descLabel.getStyleClass().add("tool-desc");
        descLabel.setWrapText(true);
        descLabel.setMaxWidth(Double.MAX_VALUE);
        VBox.setVgrow(descLabel, Priority.ALWAYS);

        // ── Tag ────────────────────────────────────────
        boolean isPlugin = !"builtin".equals(plugin.getType());
        Label tag = new Label(isPlugin ? "Plugin" : "Built-in");
        tag.getStyleClass().addAll("tool-tag", isPlugin ? "tool-tag-plugin" : "");

        getChildren().addAll(iconWrap, nameLabel, descLabel, tag);

        // ── Hover animation ─────────────────────────────────────
        ScaleTransition hoverIn  = new ScaleTransition(Duration.millis(150), this);
        ScaleTransition hoverOut = new ScaleTransition(Duration.millis(150), this);
        hoverIn.setToX(1.03); hoverIn.setToY(1.03);
        hoverOut.setToX(1.0); hoverOut.setToY(1.0);

        setOnMouseEntered(e -> { hoverOut.stop(); hoverIn.play(); });
        setOnMouseExited( e -> { hoverIn.stop(); hoverOut.play(); });

        // ── Click animation + callback ───────────────────────────────
        setOnMouseClicked(e -> {
            ScaleTransition click = new ScaleTransition(Duration.millis(100), this);
            click.setToX(0.97); click.setToY(0.97);
            click.setAutoReverse(true); click.setCycleCount(2);
            click.setOnFinished(ev -> onSelect.accept(plugin));
            click.play();
        });

        // ── Entry animation ─────────────────────────────────────
        setOpacity(0);
        setScaleX(0.94); setScaleY(0.94);
        setTranslateY(8);

        FadeTransition ft = new FadeTransition(Duration.millis(280), this);
        ft.setToValue(1);
        TranslateTransition tt = new TranslateTransition(Duration.millis(280), this);
        tt.setToY(0);
        ScaleTransition st = new ScaleTransition(Duration.millis(280), this);
        st.setToX(1); st.setToY(1);

        ParallelTransition entry = new ParallelTransition(ft, tt, st);
        entry.setInterpolator(new Interpolator() {
            @Override protected double curve(double t) {
                // Simple spring curve
                return 1 - Math.pow(1 - t, 3) * Math.cos(t * Math.PI * 2);
            }
        });
        // Delay set by caller, see ToolGrid
        entry.play();

        setCursor(javafx.scene.Cursor.HAND);
    }

    public SwissKitJPlugin getPlugin() { return plugin; }
}

package fan.summer.api.sidebar;

import javafx.animation.Interpolator;
import javafx.animation.ScaleTransition;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.control.Label;
import javafx.scene.layout.HBox;
import javafx.scene.layout.Priority;
import javafx.scene.layout.Region;
import javafx.scene.layout.VBox;
import javafx.util.Duration;

import java.util.ArrayList;
import java.util.List;
import java.util.function.Consumer;

/**
 * Left navigation sidebar.
 * Listen for category switch events via setOnCategorySelect.
 */
public class Sidebar extends VBox {

    public record Category(String id, String icon, String label, int count, boolean isNew) {}

    private final List<NavItem> navItems = new ArrayList<>();
    private NavItem activeItem;
    private Consumer<String> onCategorySelect;
    private Runnable onSettingsSelect;

    public Sidebar() {
        getStyleClass().add("sidebar");
        setPrefWidth(220);
        setMinWidth(200);
        setMaxWidth(260);
        build();
    }

    public void setOnCategorySelect(Consumer<String> handler) {
        this.onCategorySelect = handler;
    }

    public void setOnSettingsSelect(Runnable handler) {
        this.onSettingsSelect = handler;
    }

    /** Dynamically update plugin category badge numbers */
    public void updateBadge(String categoryId, int count) {
        navItems.stream()
            .filter(item -> item.getCategoryId().equals(categoryId))
            .findFirst()
            .ifPresent(item -> item.setBadge(count));
    }

    // ── Build static navigation structure ──────────────────────────────────

    private void build() {
        setSpacing(0);

        // ── Tools section ────────────────────────────────────
        getChildren().add(sectionLabel("TOOLS"));
        addNavItem("all",     "⊞", "All Tools", 12, false);
        addNavItem("text",    "✏️", "Text Processing",  4, false);
        addNavItem("image",   "🖼", "Image Processing",  3, false);
        addNavItem("dev",     "⌨️", "Developer Tools",  3, false);
        addNavItem("net",     "📡", "Network Tools",  2, false);

        getChildren().add(divider());

        // ── Plugins section ────────────────────────────────────
        getChildren().add(sectionLabel("PLUGINS"));
        addNavItem("plugins", "🧩", "Installed Plugins", 3, true);
        addNavItem("store",   "🏪", "Plugin Store",   0, false);

        getChildren().add(divider());

        // ── Favorites section ────────────────────────────────────
        getChildren().add(sectionLabel("收藏"));
        addNavItem("fav", "⭐", "My Favorites", 5, false);

        // ── Bottom spacer + Settings ──────────────────────────────
        Region spacer = new Region();
        VBox.setVgrow(spacer, Priority.ALWAYS);
        getChildren().add(spacer);
        getChildren().add(divider());
        addSettingsItem("⚙️", "设置");

        // 默认激活"All Tools"
        if (!navItems.isEmpty()) {
            activate(navItems.get(0), false);
        }
    }

    private void addNavItem(String id, String icon, String label, int count, boolean isNew) {
        NavItem item = new NavItem(id, icon, label, count, isNew);
        item.setOnMouseClicked(e -> activate(item, true));
        navItems.add(item);
        getChildren().add(item);
    }

    private void addSettingsItem(String icon, String label) {
        NavItem item = new NavItem("settings", icon, label, 0, false);
        item.setOnMouseClicked(e -> {
            if (onSettingsSelect != null) onSettingsSelect.run();
        });
        getChildren().add(item);
    }

    private void activate(NavItem item, boolean fireEvent) {
        if (activeItem != null) activeItem.setActive(false);
        activeItem = item;
        item.setActive(true);
        if (fireEvent && onCategorySelect != null) {
            onCategorySelect.accept(item.getCategoryId());
        }
    }

    // ── Helper node factory ──────────────────────────────────────

    private Label sectionLabel(String text) {
        Label l = new Label(text.toUpperCase());
        l.getStyleClass().add("sidebar-section-label");
        return l;
    }

    private Region divider() {
        Region d = new Region();
        d.getStyleClass().add("sidebar-divider");
        d.setPrefHeight(1);
        VBox.setMargin(d, new Insets(6, 4, 6, 4));
        return d;
    }

    // ════════════════════════════════════════════════════
    // Inner class: single navigation item
    // ════════════════════════════════════════════════════

    public static class NavItem extends HBox {

        private final String categoryId;
        private final Label  badgeLabel;
        private boolean active = false;

        public NavItem(String id, String icon, String label, int count, boolean isNew) {
            this.categoryId = id;

            getStyleClass().add("nav-item");
            setAlignment(Pos.CENTER_LEFT);
            setSpacing(10);
            setPrefHeight(34);

            Label iconLabel = new Label(icon);
            iconLabel.setStyle("-fx-font-size: 14px; -fx-min-width: 18px; -fx-alignment: center;");

            Label textLabel = new Label(label);
            textLabel.setStyle("-fx-font-size: 13px;");
            HBox.setHgrow(textLabel, Priority.ALWAYS);

            badgeLabel = new Label(count > 0 ? String.valueOf(count) : "");
            badgeLabel.getStyleClass().add(isNew ? "nav-badge nav-badge-new" : "nav-badge");
            badgeLabel.setVisible(count > 0);

            getChildren().addAll(iconLabel, textLabel, badgeLabel);
            setCursor(javafx.scene.Cursor.HAND);
        }

        public String getCategoryId() { return categoryId; }

        public void setActive(boolean active) {
            this.active = active;
            if (active) {
                getStyleClass().add("active");
                // Spring scale feedback
                ScaleTransition st = new ScaleTransition(Duration.millis(160), this);
                st.setFromX(0.97); st.setFromY(0.97);
                st.setToX(1.0); st.setToY(1.0);
                st.setInterpolator(Interpolator.SPLINE(0.34, 0.9, 0.64, 1.0));
                st.play();
            } else {
                getStyleClass().remove("active");
            }
        }

        public void setBadge(int count) {
            badgeLabel.setText(count > 0 ? String.valueOf(count) : "");
            badgeLabel.setVisible(count > 0);
        }

        public boolean isActive() { return active; }
    }
}

package fan.summer.api.titlebar;

import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.control.Button;
import javafx.scene.control.Label;
import javafx.scene.control.Tooltip;
import javafx.scene.layout.HBox;
import javafx.scene.layout.Priority;
import javafx.scene.layout.StackPane;
import javafx.stage.Stage;

/**
 * Custom macOS-style title bar.
 * Contains: traffic light buttons / centered title / right-side action buttons.
 * Supports dragging to move window (with FX-BorderlessScene or directly bound to Stage).
 */
public class TitleBar extends HBox {

    private double dragOffsetX, dragOffsetY;

    public TitleBar(Stage stage, Runnable onSettings) {
        getStyleClass().add("titlebar");
        setAlignment(Pos.CENTER_LEFT);
        setPrefHeight(44);
        setMinHeight(44);
        setPadding(new Insets(0, 12, 0, 16));

        // ── Traffic lights ──────────────────────────────────────
        HBox lights = buildTrafficLights(stage);

        // ── Centered title (wrapped with StackPane for absolute centering) ───
        Label titleLabel = new Label("ToolBox");
        titleLabel.getStyleClass().add("titlebar-title");
        StackPane titleWrap = new StackPane(titleLabel);
        HBox.setHgrow(titleWrap, Priority.ALWAYS);

        // ── Right-side buttons ────────────────────────────────────
        HBox actions = new HBox(8);
        actions.setAlignment(Pos.CENTER_RIGHT);
        actions.getChildren().addAll(
            titlebarBtn("🔔", "通知", () -> {}),
            titlebarBtn("⚙️", "设置", onSettings)
        );

        getChildren().addAll(lights, titleWrap, actions);

        // ── Window drag ────────────────────────────────────
        setOnMousePressed(e -> {
            dragOffsetX = e.getSceneX();
            dragOffsetY = e.getSceneY();
        });
        setOnMouseDragged(e -> {
            stage.setX(e.getScreenX() - dragOffsetX);
            stage.setY(e.getScreenY() - dragOffsetY);
        });
    }

    // ── Traffic lights ────────────────────────────────────────────

    private HBox buildTrafficLights(Stage stage) {
        Button close = trafficLight("traffic-light-close", "✕");
        Button min   = trafficLight("traffic-light-min",   "−");
        Button max   = trafficLight("traffic-light-max",   "+");

        close.setOnAction(e -> stage.close());
        min.setOnAction(e   -> stage.setIconified(true));
        max.setOnAction(e   -> stage.setMaximized(!stage.isMaximized()));

        HBox box = new HBox(8, close, min, max);
        box.setAlignment(Pos.CENTER_LEFT);

        // Only show icon on hover
        Label[] icons = {
            findIcon(close), findIcon(min), findIcon(max)
        };
        box.setOnMouseEntered(e -> { for (Label l : icons) l.setOpacity(1); });
        box.setOnMouseExited( e -> { for (Label l : icons) l.setOpacity(0); });
        return box;
    }

    private Button trafficLight(String colorClass, String iconText) {
        Label icon = new Label(iconText);
        icon.setStyle(
            "-fx-font-size: 7px; -fx-text-fill: rgba(0,0,0,0.5);" +
            "-fx-alignment: center;"
        );
        icon.setOpacity(0);

        StackPane content = new StackPane(icon);
        content.setPrefSize(12, 12);

        Button btn = new Button();
        btn.setGraphic(content);
        btn.getStyleClass().addAll("traffic-light", colorClass);
        btn.setPrefSize(12, 12);
        btn.setMinSize(12, 12);
        btn.setMaxSize(12, 12);
        btn.setPadding(Insets.EMPTY);
        btn.setStyle("-fx-background-insets: 0; -fx-padding: 0;");
        return btn;
    }

    private Label findIcon(Button btn) {
        // Extract Label from StackPane
        StackPane sp = (StackPane) btn.getGraphic();
        return (Label) sp.getChildren().get(0);
    }

    // ── Title bar tool buttons ────────────────────────────────────

    private Button titlebarBtn(String icon, String tooltip, Runnable action) {
        Button btn = new Button(icon);
        btn.setTooltip(new Tooltip(tooltip));
        btn.setStyle(
            "-fx-background-color: rgba(255,255,255,0.055);" +
            "-fx-border-color: rgba(255,255,255,0.10);" +
            "-fx-border-width: 1; -fx-border-radius: 8;" +
            "-fx-background-radius: 8;" +
            "-fx-text-fill: rgba(255,255,255,0.50);" +
            "-fx-font-size: 13px; -fx-cursor: hand;" +
            "-fx-pref-width: 28px; -fx-pref-height: 28px;" +
            "-fx-min-width: 28px; -fx-min-height: 28px;"
        );
        btn.setOnMouseEntered(e -> btn.setStyle(btn.getStyle()
            .replace("rgba(255,255,255,0.055)", "rgba(255,255,255,0.09)")
            .replace("rgba(255,255,255,0.10)",  "rgba(255,255,255,0.22)")
            .replace("rgba(255,255,255,0.50)",  "rgba(255,255,255,0.92)")
        ));
        btn.setOnMouseExited(e -> btn.setStyle(btn.getStyle()
            .replace("rgba(255,255,255,0.09)", "rgba(255,255,255,0.055)")
            .replace("rgba(255,255,255,0.22)", "rgba(255,255,255,0.10)")
            .replace("rgba(255,255,255,0.92)", "rgba(255,255,255,0.50)")
        ));
        btn.setOnAction(e -> action.run());
        return btn;
    }
}

