package fan.summer.buildintool.excelsplitter;

import java.nio.file.Path;
import java.util.List;

/**
 * Configuration collected across wizard steps, passed between steps.
 */
public class SplitConfig {

    public enum SplitMode {
        BY_SHEET("By Sheet"),
        BY_COLUMN("By Column Value"),
        BY_ROW_COUNT("By Row Count");

        public final String label;
        SplitMode(String label) { this.label = label; }
    }

    // Step 1: Source file
    public Path   sourceFile;
    public List<String> sheetNames;   // All sheet names in source file

    // Step 2: Split mode
    public SplitMode mode = SplitMode.BY_SHEET;

    // BY_COLUMN 专用
    public String splitColumn;        // Column header name
    public int    splitColumnIndex;   // Column index (0-based)

    // BY_ROW_COUNT 专用
    public int rowsPerFile = 1000;

    // BY_SHEET 专用
    public List<String> selectedSheets; // Sheets to split, null means all

    // Step 3: Output settings
    public Path   outputDir;
    public String filePrefix = "";    // Output file name prefix
    public boolean keepHeader = true; // Whether to keep header when splitting by column/row

    @Override
    public String toString() {
        return "SplitConfig{mode=" + mode + ", source=" + sourceFile + "}";
    }
}

package fan.summer.api;

import javafx.scene.Node;

/**
 * 所有工具（内置或插件）都实现此接口。
 * 主程序只依赖这个接口，与具体实现完全解耦。
 *
 * 插件开发者步骤：
 *   1. 在 pom.xml 中以 provided scope 依赖 SwissKitJ-Api：
 *      {@code
 *      <dependency>
 *          <groupId>fan.summer.api</groupId>
 *          <artifactId>SwissKitJ-Api</artifactId>
 *          <version>3.0.0</version>
 *          <scope>provided</scope>
 *      </dependency>
 *      }
 *   2. 实现此接口
 *   3. 在 META-INF/services/fan.summer.api.SwissKitJPlugin 中声明实现类全限定名
 *   4. 将插件打包为 fat-JAR（包含所有私有依赖），放入主程序的 plugins/ 目录
 */
public interface SwissKitJPlugin {

    // ── 元信息（用于侧边栏、搜索、详情面板） ────────────

    /** 全局唯一 ID，建议用反向域名：com.example.my-tool */
    String getId();

    /** 显示名称，如"JSON 格式化" */
    String getName();

    /** 一句话描述，显示在卡片和详情面板 */
    String getDescription();

    /** 分类，对应侧边栏导航：dev / text / image / net / other */
    String getCategory();

    /** 版本号，如"1.0.0" */
    String getVersion();

    /**
     * 图标字符（Emoji 或单字符），显示在卡片图标区。
     * 若需要自定义图标节点，可覆盖 getIconNode()。
     */
    String getIconText();

    /**
     * 图标背景色 CSS 类，对应 glass.css 中的色彩变体：
     *   ic-blue / ic-purple / ic-teal / ic-amber / ic-red / ic-pink / ic-gray
     */
    default String getIconStyle() { return "ic-blue"; }

    /**
     * 类型标识：内置工具返回 "builtin"，外部插件返回 "plugin"（默认）。
     * 用于卡片标签颜色和详情面板展示。
     */
    default String getType() { return "plugin"; }

    // ── UI 生命周期 ──────────────────────────────────────

    /**
     * 返回此工具的主界面节点。
     * 主程序将其嵌入内容区的 StackPane。
     * 首次调用时创建，之后可复用同一实例。
     */
    Node createView();

    /**
     * 工具被切换到前台时调用（可在此恢复状态、启动定时器等）。
     * 默认空实现，按需覆盖。
     */
    default void onActivate() {}

    /**
     * 工具被切换到后台时调用（应暂停定时器、保存临时状态等）。
     * 默认空实现，按需覆盖。
     */
    default void onDeactivate() {}

    /**
     * 插件被卸载前调用（应释放所有资源：线程、文件句柄等）。
     * 默认空实现，按需覆盖。
     */
    default void onUnload() {}
}

