package fan.summer.buildintool.excelsplitter;

import org.apache.poi.ss.usermodel.*;
import org.apache.poi.xssf.usermodel.XSSFWorkbook;

import java.io.FileOutputStream;
import java.nio.file.*;
import java.util.*;
import java.util.function.BiConsumer;

/**
 * Excel split core logic.
 * Does not depend on JavaFX, can be safely called in background threads.
 *
 * Progress callback: BiConsumer<current progress (0~1), status description>
 */
public class ExcelSplitter {

    public record SplitResult(int fileCount, List<Path> outputFiles) {}

    private final SplitConfig           config;
    private final BiConsumer<Double, String> progress;

    public ExcelSplitter(SplitConfig config, BiConsumer<Double, String> progress) {
        this.config   = config;
        this.progress = progress;
    }

    public SplitResult split() throws Exception {
        progress.accept(0.0, "Reading file…");

        try (Workbook src = WorkbookFactory.create(config.sourceFile.toFile(), null, true)) {
            return switch (config.mode) {
                case BY_SHEET      -> splitBySheet(src);
                case BY_COLUMN     -> splitByColumn(src);
                case BY_ROW_COUNT  -> splitByRowCount(src);
            };
        }
    }

    // ── Split by sheet ─────────────────────────────────────

    private SplitResult splitBySheet(Workbook src) throws Exception {
        List<String> targets = config.selectedSheets != null
            ? config.selectedSheets
            : config.sheetNames;

        List<Path> outputs = new ArrayList<>();
        for (int i = 0; i < targets.size(); i++) {
            String name = targets.get(i);
            progress.accept((double) i / targets.size(), "Processing sheet：" + name);

            Sheet sheet = src.getSheet(name);
            if (sheet == null) continue;

            Path out = outputPath(sanitize(name));
            try (Workbook wb = new XSSFWorkbook();
                 FileOutputStream fos = new FileOutputStream(out.toFile())) {
                copySheet(src, sheet, wb);
                wb.write(fos);
            }
            outputs.add(out);
        }
        progress.accept(1.0, "Done");
        return new SplitResult(outputs.size(), outputs);
    }

    // ── Split by column value ────────────────────────────────────────

    private SplitResult splitByColumn(Workbook src) throws Exception {
        Sheet sheet = src.getSheetAt(0);
        Row header  = config.keepHeader ? sheet.getRow(sheet.getFirstRowNum()) : null;
        int  colIdx = config.splitColumnIndex;

        // Group rows by column value
        Map<String, List<Row>> groups = new LinkedHashMap<>();
        for (int r = sheet.getFirstRowNum() + (config.keepHeader ? 1 : 0);
             r <= sheet.getLastRowNum(); r++) {
            Row row = sheet.getRow(r);
            if (row == null) continue;
            String key = cellValue(row.getCell(colIdx));
            groups.computeIfAbsent(key, k -> new ArrayList<>()).add(row);
        }

        List<Path> outputs = new ArrayList<>();
        int i = 0;
        for (Map.Entry<String, List<Row>> entry : groups.entrySet()) {
            progress.accept((double) i / groups.size(), "Writing：" + entry.getKey());
            Path out = outputPath(sanitize(entry.getKey()));
            writeRows(src, sheet, header, entry.getValue(), out);
            outputs.add(out);
            i++;
        }
        progress.accept(1.0, "Done");
        return new SplitResult(outputs.size(), outputs);
    }

    // ── Split by row count ────────────────────────────────────────

    private SplitResult splitByRowCount(Workbook src) throws Exception {
        Sheet sheet   = src.getSheetAt(0);
        Row   header  = config.keepHeader ? sheet.getRow(sheet.getFirstRowNum()) : null;
        int   start   = sheet.getFirstRowNum() + (config.keepHeader ? 1 : 0);
        int   total   = sheet.getLastRowNum() - start + 1;
        int   batchSz = config.rowsPerFile;

        List<Path> outputs = new ArrayList<>();
        int part = 1;
        for (int r = start; r <= sheet.getLastRowNum(); r += batchSz) {
            progress.accept((double)(r - start) / total, "Writing part " + part + "…");
            List<Row> batch = new ArrayList<>();
            for (int rr = r; rr < r + batchSz && rr <= sheet.getLastRowNum(); rr++) {
                Row row = sheet.getRow(rr);
                if (row != null) batch.add(row);
            }
            Path out = outputPath("part_" + String.format("%03d", part));
            writeRows(src, sheet, header, batch, out);
            outputs.add(out);
            part++;
        }
        progress.accept(1.0, "Done");
        return new SplitResult(outputs.size(), outputs);
    }

    // ── Helper: write rows ─────────────────────────────────────

    private void writeRows(Workbook src, Sheet srcSheet,
                           Row header, List<Row> rows, Path dest) throws Exception {
        try (Workbook wb = new XSSFWorkbook();
             FileOutputStream fos = new FileOutputStream(dest.toFile())) {
            Sheet out = wb.createSheet(srcSheet.getSheetName());
            int rowNum = 0;
            if (header != null) {
                copyRow(src, wb, header, out.createRow(rowNum++));
            }
            for (Row src_row : rows) {
                copyRow(src, wb, src_row, out.createRow(rowNum++));
            }
            // Auto column width (only first 50 columns to avoid performance issues)
            int cols = Math.min(srcSheet.getRow(srcSheet.getFirstRowNum()) != null
                ? srcSheet.getRow(srcSheet.getFirstRowNum()).getLastCellNum() : 10, 50);
            for (int c = 0; c < cols; c++) out.autoSizeColumn(c);
            wb.write(fos);
        }
    }

    // ── Helper: sheet copy ─────────────────────────────────

    private void copySheet(Workbook srcWb, Sheet src, Workbook destWb) {
        Sheet dest = destWb.createSheet(src.getSheetName());
        for (int r = src.getFirstRowNum(); r <= src.getLastRowNum(); r++) {
            Row srcRow = src.getRow(r);
            if (srcRow == null) continue;
            copyRow(srcWb, destWb, srcRow, dest.createRow(r));
        }
        // Column width
        int cols = src.getRow(src.getFirstRowNum()) != null
            ? src.getRow(src.getFirstRowNum()).getLastCellNum() : 0;
        for (int c = 0; c < Math.min(cols, 50); c++) dest.autoSizeColumn(c);
    }

    private void copyRow(Workbook srcWb, Workbook destWb, Row src, Row dest) {
        dest.setHeight(src.getHeight());
        for (int c = src.getFirstCellNum(); c < src.getLastCellNum(); c++) {
            Cell srcCell  = src.getCell(c);
            Cell destCell = dest.createCell(c);
            if (srcCell == null) continue;
            copyCellValue(srcCell, destCell);
        }
    }

    private void copyCellValue(Cell src, Cell dest) {
        switch (src.getCellType()) {
            case STRING  -> dest.setCellValue(src.getStringCellValue());
            case NUMERIC -> {
                if (DateUtil.isCellDateFormatted(src))
                    dest.setCellValue(src.getDateCellValue());
                else
                    dest.setCellValue(src.getNumericCellValue());
            }
            case BOOLEAN -> dest.setCellValue(src.getBooleanCellValue());
            case FORMULA -> dest.setCellValue(src.getRawValue()); // preserve computed result
            case BLANK   -> dest.setBlank();
            default      -> dest.setCellValue(src.toString());
        }
    }

    // ── Helper: utility methods ────────────────────────────────────

    private String cellValue(Cell cell) {
        if (cell == null) return "(empty)";
        return switch (cell.getCellType()) {
            case STRING  -> cell.getStringCellValue().trim();
            case NUMERIC -> String.valueOf((long) cell.getNumericCellValue());
            case BOOLEAN -> String.valueOf(cell.getBooleanCellValue());
            default      -> cell.toString().trim();
        };
    }

    /** Strip characters that are illegal in file names */
    private String sanitize(String name) {
        return name.replaceAll("[\\\\/:*?\"<>|]", "_").trim();
    }

    private Path outputPath(String name) {
        String prefix = config.filePrefix.isBlank() ? "" : config.filePrefix + "_";
        return config.outputDir.resolve(prefix + name + ".xlsx");
    }
}

package fan.summer.buildintool.excelsplitter;

import java.nio.file.Path;
import java.util.List;

/**
 * Configuration collected across wizard steps, passed between steps.
 */
public class SplitConfig {

    public enum SplitMode {
        BY_SHEET("By Sheet"),
        BY_COLUMN("By Column Value"),
        BY_ROW_COUNT("By Row Count");

        public final String label;
        SplitMode(String label) { this.label = label; }
    }

    // Step 1: Source file
    public Path   sourceFile;
    public List<String> sheetNames;   // All sheet names in source file

    // Step 2: Split mode
    public SplitMode mode = SplitMode.BY_SHEET;

    // BY_COLUMN specific
    public String splitColumn;        // Column header name
    public int    splitColumnIndex;   // Column index (0-based)

    // BY_ROW_COUNT specific
    public int rowsPerFile = 1000;

    // BY_SHEET specific
    public List<String> selectedSheets; // Sheets to split, null means all

    // Step 3: Output settings
    public Path   outputDir;
    public String filePrefix = "";    // Output file name prefix
    public boolean keepHeader = true; // Whether to keep header when splitting by column/row

    @Override
    public String toString() {
        return "SplitConfig{mode=" + mode + ", source=" + sourceFile + "}";
    }
}

package fan.summer.ui.titlebar;

import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.control.Button;
import javafx.scene.control.Label;
import javafx.scene.control.Tooltip;
import javafx.scene.layout.HBox;
import javafx.scene.layout.Priority;
import javafx.scene.layout.StackPane;
import javafx.stage.Stage;

/**
 * Custom macOS-style title bar.
 * Contains: traffic light buttons / centered title / right-side action buttons.
 * Supports dragging to move window (with FX-BorderlessScene or directly bound to Stage).
 */
public class TitleBar extends HBox {

    private double dragOffsetX, dragOffsetY;

    public TitleBar(Stage stage, Runnable onSettings) {
        getStyleClass().add("titlebar");
        setAlignment(Pos.CENTER_LEFT);
        setPrefHeight(44);
        setMinHeight(44);
        setPadding(new Insets(0, 12, 0, 16));

        // ── Traffic lights ──────────────────────────────────────
        HBox lights = buildTrafficLights(stage);

        // ── Centered title (wrapped with StackPane for absolute centering) ───
        Label titleLabel = new Label("ToolBox");
        titleLabel.getStyleClass().add("titlebar-title");
        StackPane titleWrap = new StackPane(titleLabel);
        HBox.setHgrow(titleWrap, Priority.ALWAYS);

        // ── Right-side buttons ────────────────────────────────────
        HBox actions = new HBox(8);
        actions.setAlignment(Pos.CENTER_RIGHT);
        actions.getChildren().addAll(
            titlebarBtn("🔔", "Notifications", () -> {}),
            titlebarBtn("⚙️", "Settings", onSettings)
        );

        getChildren().addAll(lights, titleWrap, actions);

        // ── Window drag ────────────────────────────────────
        setOnMousePressed(e -> {
            dragOffsetX = e.getSceneX();
            dragOffsetY = e.getSceneY();
        });
        setOnMouseDragged(e -> {
            stage.setX(e.getScreenX() - dragOffsetX);
            stage.setY(e.getScreenY() - dragOffsetY);
        });
    }

    // ── Traffic lights ────────────────────────────────────────────

    private HBox buildTrafficLights(Stage stage) {
        Button close = trafficLight("traffic-light-close", "✕");
        Button min   = trafficLight("traffic-light-min",   "−");
        Button max   = trafficLight("traffic-light-max",   "+");

        close.setOnAction(e -> stage.close());
        min.setOnAction(e   -> stage.setIconified(true));
        max.setOnAction(e   -> stage.setMaximized(!stage.isMaximized()));

        HBox box = new HBox(8, close, min, max);
        box.setAlignment(Pos.CENTER_LEFT);

        // Only show icon on hover
        Label[] icons = {
            findIcon(close), findIcon(min), findIcon(max)
        };
        box.setOnMouseEntered(e -> { for (Label l : icons) l.setOpacity(1); });
        box.setOnMouseExited( e -> { for (Label l : icons) l.setOpacity(0); });
        return box;
    }

    private Button trafficLight(String colorClass, String iconText) {
        Label icon = new Label(iconText);
        icon.setStyle(
            "-fx-font-size: 7px; -fx-text-fill: rgba(0,0,0,0.5);" +
            "-fx-alignment: center;"
        );
        icon.setOpacity(0);

        StackPane content = new StackPane(icon);
        content.setPrefSize(12, 12);

        Button btn = new Button();
        btn.setGraphic(content);
        btn.getStyleClass().addAll("traffic-light", colorClass);
        btn.setPrefSize(12, 12);
        btn.setMinSize(12, 12);
        btn.setMaxSize(12, 12);
        btn.setPadding(Insets.EMPTY);
        btn.setStyle("-fx-background-insets: 0; -fx-padding: 0;");
        return btn;
    }

    private Label findIcon(Button btn) {
        // Extract Label from StackPane
        StackPane sp = (StackPane) btn.getGraphic();
        return (Label) sp.getChildren().get(0);
    }

    // ── Title bar tool buttons ────────────────────────────────────

    private Button titlebarBtn(String icon, String tooltip, Runnable action) {
        Button btn = new Button(icon);
        btn.setTooltip(new Tooltip(tooltip));
        btn.setStyle(
            "-fx-background-color: rgba(255,255,255,0.055);" +
            "-fx-border-color: rgba(255,255,255,0.10);" +
            "-fx-border-width: 1; -fx-border-radius: 8;" +
            "-fx-background-radius: 8;" +
            "-fx-text-fill: rgba(255,255,255,0.50);" +
            "-fx-font-size: 13px; -fx-cursor: hand;" +
            "-fx-pref-width: 28px; -fx-pref-height: 28px;" +
            "-fx-min-width: 28px; -fx-min-height: 28px;"
        );
        btn.setOnMouseEntered(e -> btn.setStyle(btn.getStyle()
            .replace("rgba(255,255,255,0.055)", "rgba(255,255,255,0.09)")
            .replace("rgba(255,255,255,0.10)",  "rgba(255,255,255,0.22)")
            .replace("rgba(255,255,255,0.50)",  "rgba(255,255,255,0.92)")
        ));
        btn.setOnMouseExited(e -> btn.setStyle(btn.getStyle()
            .replace("rgba(255,255,255,0.09)", "rgba(255,255,255,0.055)")
            .replace("rgba(255,255,255,0.22)", "rgba(255,255,255,0.10)")
            .replace("rgba(255,255,255,0.92)", "rgba(255,255,255,0.50)")
        ));
        btn.setOnAction(e -> action.run());
        return btn;
    }
}

package fan.summer.ui.sidebar;

import javafx.animation.Interpolator;
import javafx.animation.ScaleTransition;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.control.Label;
import javafx.scene.layout.HBox;
import javafx.scene.layout.Priority;
import javafx.scene.layout.Region;
import javafx.scene.layout.VBox;
import javafx.util.Duration;

import java.util.ArrayList;
import java.util.List;
import java.util.function.Consumer;

/**
 * Left navigation sidebar.
 * Listen for category switch events via setOnCategorySelect.
 */
public class Sidebar extends VBox {

    public record Category(String id, String icon, String label, int count, boolean isNew) {}

    private final List<NavItem> navItems = new ArrayList<>();
    private NavItem activeItem;
    private Consumer<String> onCategorySelect;
    private Runnable onSettingsSelect;

    public Sidebar() {
        getStyleClass().add("sidebar");
        setPrefWidth(220);
        setMinWidth(200);
        setMaxWidth(260);
        build();
    }

    public void setOnCategorySelect(Consumer<String> handler) {
        this.onCategorySelect = handler;
    }

    public void setOnSettingsSelect(Runnable handler) {
        this.onSettingsSelect = handler;
    }

    /** Dynamically update plugin category badge numbers */
    public void updateBadge(String categoryId, int count) {
        navItems.stream()
            .filter(item -> item.getCategoryId().equals(categoryId))
            .findFirst()
            .ifPresent(item -> item.setBadge(count));
    }

    // ── Build static navigation structure ──────────────────────────────────

    private void build() {
        setSpacing(0);

        // ── Tools section ────────────────────────────────────
        getChildren().add(sectionLabel("TOOLS"));
        addNavItem("all",     "⊞", "All Tools", 12, false);
        addNavItem("text",    "✏️", "Text Processing",  4, false);
        addNavItem("image",   "🖼", "Image Processing",  3, false);
        addNavItem("dev",     "⌨️", "Developer Tools",  3, false);
        addNavItem("net",     "📡", "Network Tools",  2, false);

        getChildren().add(divider());

        // ── Plugins section ────────────────────────────────────
        getChildren().add(sectionLabel("PLUGINS"));
        addNavItem("plugins", "🧩", "Installed Plugins", 3, true);
        addNavItem("store",   "🏪", "Plugin Store",   0, false);

        getChildren().add(divider());

        // ── Favorites section ────────────────────────────────────
        getChildren().add(sectionLabel("FAVORITES"));
        addNavItem("fav", "⭐", "My Favorites", 5, false);

        // ── Bottom spacer + Settings ──────────────────────────────
        Region spacer = new Region();
        VBox.setVgrow(spacer, Priority.ALWAYS);
        getChildren().add(spacer);
        getChildren().add(divider());
        addSettingsItem("⚙️", "Settings");

        // Activate "All Tools" by default
        if (!navItems.isEmpty()) {
            activate(navItems.get(0), false);
        }
    }

    private void addNavItem(String id, String icon, String label, int count, boolean isNew) {
        NavItem item = new NavItem(id, icon, label, count, isNew);
        item.setOnMouseClicked(e -> activate(item, true));
        navItems.add(item);
        getChildren().add(item);
    }

    private void addSettingsItem(String icon, String label) {
        NavItem item = new NavItem("settings", icon, label, 0, false);
        item.setOnMouseClicked(e -> {
            if (onSettingsSelect != null) onSettingsSelect.run();
        });
        getChildren().add(item);
    }

    private void activate(NavItem item, boolean fireEvent) {
        if (activeItem != null) activeItem.setActive(false);
        activeItem = item;
        item.setActive(true);
        if (fireEvent && onCategorySelect != null) {
            onCategorySelect.accept(item.getCategoryId());
        }
    }

    // ── Helper node factory ──────────────────────────────────────

    private Label sectionLabel(String text) {
        Label l = new Label(text.toUpperCase());
        l.getStyleClass().add("sidebar-section-label");
        return l;
    }

    private Region divider() {
        Region d = new Region();
        d.getStyleClass().add("sidebar-divider");
        d.setPrefHeight(1);
        VBox.setMargin(d, new Insets(6, 4, 6, 4));
        return d;
    }

    // ════════════════════════════════════════════════════
    // Inner class: single navigation item
    // ════════════════════════════════════════════════════

    public static class NavItem extends HBox {

        private final String categoryId;
        private final Label  badgeLabel;
        private boolean active = false;

        public NavItem(String id, String icon, String label, int count, boolean isNew) {
            this.categoryId = id;

            getStyleClass().add("nav-item");
            setAlignment(Pos.CENTER_LEFT);
            setSpacing(10);
            setPrefHeight(34);

            Label iconLabel = new Label(icon);
            iconLabel.setStyle("-fx-font-size: 14px; -fx-min-width: 18px; -fx-alignment: center;");

            Label textLabel = new Label(label);
            textLabel.setStyle("-fx-font-size: 13px;");
            HBox.setHgrow(textLabel, Priority.ALWAYS);

            badgeLabel = new Label(count > 0 ? String.valueOf(count) : "");
            badgeLabel.getStyleClass().add(isNew ? "nav-badge nav-badge-new" : "nav-badge");
            badgeLabel.setVisible(count > 0);

            getChildren().addAll(iconLabel, textLabel, badgeLabel);
            setCursor(javafx.scene.Cursor.HAND);
        }

        public String getCategoryId() { return categoryId; }

        public void setActive(boolean active) {
            this.active = active;
            if (active) {
                getStyleClass().add("active");
                // Spring scale feedback
                ScaleTransition st = new ScaleTransition(Duration.millis(160), this);
                st.setFromX(0.97); st.setFromY(0.97);
                st.setToX(1.0); st.setToY(1.0);
                st.setInterpolator(Interpolator.SPLINE(0.34, 0.9, 0.64, 1.0));
                st.play();
            } else {
                getStyleClass().remove("active");
            }
        }

        public void setBadge(int count) {
            badgeLabel.setText(count > 0 ? String.valueOf(count) : "");
            badgeLabel.setVisible(count > 0);
        }

        public boolean isActive() { return active; }
    }
}

